def br_money(value: float | int | None) -> str:
    value = float(value or 0)
    return f"R$ {value:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")


def br_money_short(value: float | int | None) -> str:
    value = float(value or 0)
    abs_value = abs(value)
    sign = "-" if value < 0 else ""
    if abs_value >= 1_000_000:
        txt = f"{sign}R$ {abs_value / 1_000_000:.1f} mi"
    elif abs_value >= 1_000:
        txt = f"{sign}R$ {abs_value / 1_000:.1f} mil"
    else:
        txt = f"{sign}R$ {abs_value:,.2f}"
    return txt.replace(",", "X").replace(".", ",").replace("X", ".")


def int_br(value: int | float | None) -> str:
    try:
        value = int(float(value or 0))
    except Exception:
        value = 0
    return f"{value:,}".replace(",", ".")


def to_date_str(value) -> Optional[str]:
    if pd.isna(value) or value == "":
        return None
    try:
        # Quando o Excel é lido sem openpyxl, datas podem chegar como número serial.
        if isinstance(value, (int, float)) and value > 20000:
            return pd.to_datetime(value, unit="D", origin="1899-12-30").date().isoformat()
        return pd.to_datetime(value, dayfirst=True).date().isoformat()
    except Exception:
        return None


def parse_iso_date(value: Optional[str]) -> Optional[date]:
    if not value:
        return None
    try:
        return datetime.fromisoformat(str(value)).date()
    except Exception:
        return None


def normalize_text(value) -> str:
    if pd.isna(value):
        return ""
    text = str(value).strip()
    if text.endswith(".0"):
        text = text[:-2]
    return text




def clean_history_text(value) -> str:
    """Remove ruídos vindos de planilhas antigas de cobrança."""
    txt = normalize_text(value)
    if not txt:
        return ""
    # Remove marcadores importados por engano de colunas de decisão/status e datas soltas.
    txt = re.sub(r"\bDecis[aã]o/status:\s*", "", txt, flags=re.IGNORECASE)
    txt = re.sub(r"\bDecis[aã]o\s*/\s*status\s*[:;-]?\s*", "", txt, flags=re.IGNORECASE)
    txt = re.sub(r"\b(?:19|20)\d{2}-\d{2}-\d{2}(?:\s+00:00:00)?\b", "", txt)
    txt = re.sub(r"\b(?:nan|none|nat)\b", "", txt, flags=re.IGNORECASE)
    # Remove repetições e espaços duplicados.
    txt = re.sub(r"\s+", " ", txt).strip(" -;|•")
    # Evita frases vazias após limpeza.
    if txt.lower() in {"cliente", "status", "decisao", "decisão"}:
        return ""
    return txt


def make_titulo_id(row: pd.Series) -> str:
    parts = [
        normalize_text(row.get("Filial")),
        normalize_text(row.get("Prefixo")),
        normalize_text(row.get("No. Titulo")),
        normalize_text(row.get("Parcela")),
        normalize_text(row.get("Tipo")),
        normalize_text(row.get("Cliente")),
        normalize_text(row.get("Loja")),
    ]
    return "|".join(parts).upper()


def calcular_dias_atraso(vencimento: Optional[str], ref: date) -> int:
    venc = parse_iso_date(vencimento)
    if not venc:
        return 0
    return max((ref - venc).days, 0)


def calcular_ciclo(primeira: Optional[str], ref: date) -> int:
    pri = parse_iso_date(primeira)
    if not pri:
        return 1
    return max((ref - pri).days + 1, 1)


def _xlsx_fallback_to_dataframe(file_bytes: bytes) -> pd.DataFrame:
    """Leitor simples de XLSX sem openpyxl.

    Foi incluído para evitar que o app pare no Streamlit Cloud quando o ambiente
    ainda não instalou o pacote openpyxl. Lê a primeira aba do arquivo exportado
    pelo Protheus, preservando textos, números e datas seriais do Excel.
    """
    ns = {"a": "http://schemas.openxmlformats.org/spreadsheetml/2006/main"}

    def col_to_idx(cell_ref: str) -> int:
        letters = "".join(ch for ch in cell_ref if ch.isalpha())
        idx = 0
        for ch in letters:
            idx = idx * 26 + (ord(ch.upper()) - ord("A") + 1)
        return idx - 1

    with zipfile.ZipFile(BytesIO(file_bytes)) as z:
        shared = []
        if "xl/sharedStrings.xml" in z.namelist():
            root = ET.fromstring(z.read("xl/sharedStrings.xml"))
            for si in root.findall("a:si", ns):
                texts = [t.text or "" for t in si.findall(".//a:t", ns)]
                shared.append("".join(texts))

        # Primeira planilha visível do arquivo. Para o relatório Protheus, normalmente é sheet1.xml.
        sheet_name = "xl/worksheets/sheet1.xml"
        if sheet_name not in z.namelist():
            sheets = [n for n in z.namelist() if n.startswith("xl/worksheets/sheet") and n.endswith(".xml")]
            if not sheets:
                raise ValueError("Não encontrei nenhuma aba no arquivo XLSX.")
            sheet_name = sorted(sheets)[0]

        root = ET.fromstring(z.read(sheet_name))
        rows = []
        max_cols = 0
        for row in root.findall(".//a:sheetData/a:row", ns):
            values = []
            for cell in row.findall("a:c", ns):
                idx = col_to_idx(cell.attrib.get("r", "A1"))
                while len(values) <= idx:
                    values.append(None)
                cell_type = cell.attrib.get("t")
                v = cell.find("a:v", ns)
                is_node = cell.find("a:is", ns)
                value = None
                if cell_type == "s" and v is not None:
                    try:
                        value = shared[int(v.text)]
                    except Exception:
                        value = v.text
                elif cell_type == "inlineStr" and is_node is not None:
                    value = "".join(t.text or "" for t in is_node.findall(".//a:t", ns))
                elif v is not None:
                    raw = v.text
                    try:
                        num = float(raw)
                        value = int(num) if num.is_integer() else num
                    except Exception:
                        value = raw
                values[idx] = value
            if any(v not in (None, "") for v in values):
                max_cols = max(max_cols, len(values))
                rows.append(values)

    if not rows:
        raise ValueError("A planilha está vazia.")

    rows = [r + [None] * (max_cols - len(r)) for r in rows]
    header_idx = None
    for i, row in enumerate(rows[:20]):
        normalized = [str(x).strip() if x is not None else "" for x in row]
        if "Filial" in normalized and "No. Titulo" in normalized:
            header_idx = i
            break
    if header_idx is None:
        header_idx = 0

    header = [str(x).strip() if x is not None else f"Coluna_{i+1}" for i, x in enumerate(rows[header_idx])]
    data = rows[header_idx + 1:]
    df = pd.DataFrame(data, columns=header)
    df = df.dropna(how="all")
    return df


def read_excel_upload(file) -> pd.DataFrame:
    file_bytes = file.read() if hasattr(file, "read") else bytes(file)
    try:
        df = pd.read_excel(BytesIO(file_bytes))
    except Exception as exc:
        # Fallback para ambientes onde o openpyxl não foi instalado/atualizado ainda.
        if "openpyxl" not in str(exc).lower() and "excel" not in str(exc).lower():
            raise
        df = _xlsx_fallback_to_dataframe(file_bytes)

    df.columns = [str(c).strip() for c in df.columns]

    missing = [c for c in REQUIRED_COLUMNS if c not in df.columns]
    if missing:
        raise ValueError(f"Colunas não encontradas no arquivo: {', '.join(missing)}")

    df = df.copy()
    df["titulo_id"] = df.apply(make_titulo_id, axis=1)
    df["dt_emissao_str"] = df["DT Emissao"].apply(to_date_str)
    df["vencimento_str"] = df["Vencto real"].apply(to_date_str)

    for col in ["Vlr.Titulo", "Saldo a receber", "Multa", "Juros"]:
        if col not in df.columns:
            df[col] = 0
        df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0)

    df = df.drop_duplicates(subset=["titulo_id"], keep="last")
    return df


def read_github_base(raw_url: str) -> pd.DataFrame:
    if not raw_url.strip():
        raise ValueError("Informe a URL raw do arquivo no GitHub.")
    with urlopen(raw_url.strip(), timeout=30) as response:
        data = response.read()
    return read_excel_upload(data)






def get_config(chave: str, default: str = "") -> str:
    conn = get_conn()
    try:
        row = conn.execute("SELECT valor FROM config WHERE chave = ?", (chave,)).fetchone()
        return str(row["valor"] or "") if row else default
    finally:
        conn.close()


def set_config(chave: str, valor: str) -> None:
    conn = get_conn()
    try:
        now = datetime.now().isoformat(timespec="seconds")
        conn.execute(
            """
            INSERT INTO config (chave, valor, updated_at)
            VALUES (?, ?, ?)
            ON CONFLICT(chave) DO UPDATE SET valor = excluded.valor, updated_at = excluded.updated_at
            """,
            (chave, str(valor or "").strip(), now),
        )
        conn.commit()
    finally:
        conn.close()


def read_excel_any(file_or_bytes) -> pd.DataFrame:
    file_bytes = file_or_bytes.read() if hasattr(file_or_bytes, "read") else bytes(file_or_bytes)
    try:
        df = pd.read_excel(BytesIO(file_bytes))
    except Exception:
        try:
            df = pd.read_csv(BytesIO(file_bytes), sep=None, engine="python")
        except Exception:
            df = _xlsx_fallback_to_dataframe(file_bytes)

    # Alguns relatórios Protheus/MATR021 vêm com uma linha de título antes do cabeçalho real.
    # Quando identificamos uma linha contendo campos como Codigo/Loja/Nome, promovemos essa linha
    # para cabeçalho. Isso permite usar o MATR021 diretamente, sem editar o Excel.
    try:
        header_idx = None
        for i in range(min(15, len(df))):
            vals = [normalize_col_key(v) for v in df.iloc[i].tolist()]
            has_codigo = any(v in {"codigo", "codigocliente", "cliente"} for v in vals)
            has_loja = any(v in {"loja", "lojacliente"} for v in vals)
            has_nome = any(v in {"nome", "razaosocial", "nomecliente"} for v in vals)
            if has_codigo and has_loja and has_nome:
                header_idx = i
                break
        if header_idx is not None:
            new_cols = [str(c).strip() if str(c).strip() and str(c).lower() != "nan" else f"Coluna_{j+1}" for j, c in enumerate(df.iloc[header_idx].tolist())]
            df = df.iloc[header_idx + 1:].copy()
            df.columns = new_cols
    except Exception:
        pass

    df.columns = [str(c).strip() for c in df.columns]
    return df.dropna(how="all")


def normalize_col_key(value) -> str:
    txt = normalize_text(value).lower()
    txt = re.sub(r"[áàãâä]", "a", txt)
    txt = re.sub(r"[éèêë]", "e", txt)
    txt = re.sub(r"[íìîï]", "i", txt)
    txt = re.sub(r"[óòõôö]", "o", txt)
    txt = re.sub(r"[úùûü]", "u", txt)
    txt = re.sub(r"ç", "c", txt)
    return re.sub(r"[^a-z0-9]+", "", txt)


def find_col(df: pd.DataFrame, candidates: list[str]) -> Optional[str]:
    lookup = {normalize_col_key(c): c for c in df.columns}
    for cand in candidates:
        key = normalize_col_key(cand)
        if key in lookup:
            return lookup[key]
    # busca aproximada: o candidato contido no nome da coluna
    for cand in candidates:
        key = normalize_col_key(cand)
        for col_key, col in lookup.items():
            if key and (key in col_key or col_key in key):
                return col
    return None



def _has_col(df: pd.DataFrame, candidates: list[str]) -> bool:
    return find_col(df, candidates) is not None


def normalize_faturamento_base_columns(df: pd.DataFrame) -> pd.DataFrame:
    """Adapta formatos de relatório de faturamento/Protheus para o layout interno.

    Suporta o relatório RFATEQP01 / Relação de Pedido X Faturamento:
    - Numero -> Nota Fiscal/Pedido
    - Nome -> Vendedor/Representante, quando existir Vendedor 1
    - Nome Espec. -> Gerente/Especialista, como fallback
    - Valor Bruto/Vlr.Total -> valor de peso para consolidação
    """
    out_df = df.copy()
    out_df.columns = [str(c).strip() for c in out_df.columns]

    numero_col = find_col(out_df, ["Nota Fiscal", "NF", "No. Titulo", "Título", "Titulo", "Numero", "Número", "Nro Pedido", "Pedido"])
    if numero_col and not _has_col(out_df, ["Nota Fiscal", "NF", "No. Titulo", "Título", "Titulo"]):
        out_df["Nota Fiscal"] = out_df[numero_col]

    vendedor_nome_col = find_col(out_df, ["Nome Vendedor", "Nome do Vendedor", "VENDEDOR / REPRESENTANTE", "Vendedor", "Representante"])
    vendedor_codigo_col = find_col(out_df, ["Vendedor 1", "Cod Vendedor", "Código Vendedor", "Cod. Vendedor"])
    nome_generico_col = find_col(out_df, ["Nome"])
    if vendedor_codigo_col and nome_generico_col and not vendedor_nome_col:
        out_df["VENDEDOR / REPRESENTANTE"] = out_df[nome_generico_col]

    gerente_col = find_col(out_df, ["GERENTE", "Gerente", "Gerente Comercial", "Supervisor", "Coordenador"])
    espec_col = find_col(out_df, ["Nome Espec.", "Nome Espec", "Especialista", "Nome Especialista"])
    if espec_col and not gerente_col:
        out_df["GERENTE"] = out_df[espec_col]

    valor_col = find_col(out_df, ["VALOR BRUTO", "Valor Bruto", "Vlr.Total", "Valor Total", "Vlr Total"])
    if valor_col and not _has_col(out_df, ["VALOR BRUTO", "Valor Bruto"]):
        out_df["VALOR BRUTO"] = out_df[valor_col]

    return out_df


def read_faturamento_excel_any(file_or_bytes) -> pd.DataFrame:
    """Lê a base de faturamento procurando automaticamente a aba útil.

    No RFATEQP01 a primeira aba é Parametros, então precisamos escolher a aba que
    contém os dados de faturamento.
    """
    file_bytes = file_or_bytes.read() if hasattr(file_or_bytes, "read") else bytes(file_or_bytes)
    try:
        xls = pd.ExcelFile(BytesIO(file_bytes))
        best_df = None
        best_score = -1
        for sheet_name in xls.sheet_names:
            try:
                candidate = pd.read_excel(xls, sheet_name=sheet_name)
            except Exception:
                continue
            candidate = candidate.dropna(how="all")
            if candidate.empty:
                continue
            candidate.columns = [str(c).strip() for c in candidate.columns]
            norm = normalize_faturamento_base_columns(candidate)
            score = 0
            if _has_col(norm, ["Nota Fiscal", "NF", "No. Titulo", "Numero", "Pedido"]): score += 3
            if _has_col(norm, ["Cliente", "Cod Cliente", "Código Cliente"]): score += 2
            if _has_col(norm, ["Nome Cliente", "NOME DO CLIENTE", "Cliente Nome"]): score += 2
            if _has_col(norm, ["VENDEDOR / REPRESENTANTE", "Nome Vendedor", "Vendedor"]): score += 2
            if _has_col(norm, ["Segmento"]): score += 1
            if _has_col(norm, ["VALOR BRUTO", "Valor Bruto", "Vlr.Total", "Valor Total"]): score += 1
            score += min(len(norm), 100000) / 100000.0
            if score > best_score:
                best_score = score
                best_df = norm
        if best_df is not None and best_score >= 6:
            return best_df
    except Exception:
        pass

    return normalize_faturamento_base_columns(read_excel_any(file_bytes))


def _digits(value) -> str:
    return re.sub(r"\D+", "", normalize_text(value))


def normalize_note_key(value) -> str:
    """Normaliza NF/título para cruzamento seguro.

    Trata 00016843, 16843, 16843.0, NF 16843 e 003-000016843-001 como 16843.
    """
    if value is None:
        return ""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass
    txt = normalize_text(value).upper().strip()
    if not txt:
        return ""
    if re.fullmatch(r"\d+(?:[,.]0+)?", txt):
        txt = re.sub(r"[,.]0+$", "", txt)
        return (txt.lstrip("0") or "0")
    nums = re.findall(r"\d+", txt)
    if not nums:
        return re.sub(r"[^A-Z0-9]+", "", txt)
    candidate = max(nums, key=len)
    return candidate.lstrip("0") or "0"




def find_modelo_calculo_tjsp_bytes() -> Tuple[Optional[bytes], str]:
    """Localiza automaticamente o modelo oficial de cálculo TJSP (.xlsm)."""
    configured = get_config("modelo_calculo_tjsp_github", "").strip() if DB_PATH.exists() else ""

    local_candidates = [
        Path("Cálculo Inicial FUABC.xlsm"),
        Path("Calculo Inicial FUABC.xlsm"),
        Path("dados/Cálculo Inicial FUABC.xlsm"),
        Path("dados/Calculo Inicial FUABC.xlsm"),
        Path("modelo_calculo_tjsp.xlsm"),
        Path("dados/modelo_calculo_tjsp.xlsm"),
    ]
    for cand in local_candidates:
        if cand.exists() and cand.is_file():
            data = cand.read_bytes()
            if len(data) >= 500:
                return data, f"Modelo local: {cand.as_posix()}"

    if configured:
        if configured.lower().startswith(("http://", "https://")):
            try:
                with urlopen(configured, timeout=35) as response:
                    data = response.read()
                if len(data) >= 500:
                    return data, "Modelo de cálculo carregado pela URL configurada"
            except Exception as e:
                return None, f"Erro ao ler o modelo de cálculo pela URL: {e}"
        data, msg = github_get_file_bytes(configured)
        if data and len(data) >= 500:
            return data, msg

    github_candidates = [
        "Cálculo Inicial FUABC.xlsm", "Calculo Inicial FUABC.xlsm",
        "dados/Cálculo Inicial FUABC.xlsm", "dados/Calculo Inicial FUABC.xlsm",
        "modelo_calculo_tjsp.xlsm", "dados/modelo_calculo_tjsp.xlsm",
    ]
    for cand in github_candidates:
        data, msg = github_get_file_bytes(cand)
        if data and len(data) >= 500:
            return data, msg

    for base_dir in ["", "dados"]:
        for path in github_list_file_paths(base_dir):
            key = _file_name_key(path)
            if path.lower().endswith(".xlsm") and "calculo" in key and ("fuabc" in key or "tjsp" in key):
                data, msg = github_get_file_bytes(path)
                if data and len(data) >= 500:
                    return data, msg

    return None, "Modelo de cálculo TJSP não encontrado. Coloque o .xlsm na raiz do GitHub ou na pasta dados/."


def looks_like_vendedor_codigo(value) -> bool:
    """Identifica códigos comerciais que não devem aparecer no relatório como nome."""
    txt = normalize_text(value).upper().strip()
    if not txt:
        return True
    parts = [p.strip() for p in txt.split(",") if p.strip()]
    if parts and all(re.fullmatch(r"(INT|VEN|REP)?\d+", p) for p in parts):
        return True
    return bool(re.fullmatch(r"(INT|VEN|REP)\d+", txt))


def _ascii_upper(value) -> str:
    txt = normalize_text(value).strip().upper()
    txt = unicodedata.normalize("NFKD", txt)
    txt = "".join(ch for ch in txt if not unicodedata.combining(ch))
    return re.sub(r"\s+", " ", txt).strip()


def canonical_vendor_key(value) -> str:
    """Chave para unir variações do mesmo vendedor.

    Exemplos considerados iguais:
    - GOLOMBIESKI ... LT
    - GOLOMBIESKI ... LTDA
    - GOLOMBIESKI ..., LTDA.
    """
    txt = _ascii_upper(value)
    if not txt:
        return ""
    txt = re.sub(r"[^A-Z0-9]+", " ", txt)
    tokens = [t for t in txt.split() if t]
    # Sufixos societários não diferenciam o vendedor.
    suffixes = {
        "LT", "LTDA", "LIMITADA", "ME", "EPP", "EIRELI", "SLU",
        "SA", "S", "A", "S/A", "CIA", "COMPANHIA",
    }
    while tokens and tokens[-1] in suffixes:
        tokens.pop()
    return " ".join(tokens)


def canonical_vendor_display(value) -> str:
    """Nome padronizado para exibição e agrupamento."""
    txt = _ascii_upper(value)
    if not txt:
        return ""
    txt = re.sub(r"\s*[,.;]+\s*", " ", txt)
    txt = re.sub(r"\s+", " ", txt).strip()
    # Corrige abreviação truncada recorrente da base.
    txt = re.sub(r"\bLT\.?$", "LTDA", txt)
    txt = re.sub(r"\bLIMITADA$", "LTDA", txt)
    return txt


def canonical_manager_display(value) -> str:
    txt = _ascii_upper(value)
    txt = re.sub(r"[^A-Z0-9 ]+", " ", txt)
    return re.sub(r"\s+", " ", txt).strip()


def canonical_segment_display(value) -> str:
    txt = _ascii_upper(value)
    txt = re.sub(r"\s+", " ", txt).strip()
    return txt


def should_replace_auto_field(current_value, origin_value: str = "") -> bool:
    """Troca somente campos vazios ou claramente automáticos/códigos."""
    txt = normalize_text(current_value)
    origin = normalize_text(origin_value).upper()
    if not txt:
        return True
    if origin == "BASE BI":
        return True
    if looks_like_vendedor_codigo(txt):
        return True
    # Corrige combinações criadas automaticamente, ex.: "AMAURI, RENATO".
    if "," in txt:
        return True
    return False


def should_replace_segment(current_value, origin_value: str = "") -> bool:
    txt = normalize_text(current_value)
    origin = normalize_text(origin_value).upper()
    return (not txt) or origin == "BASE BI" or "," in txt or txt.upper() == "VÁRIOS"


def choose_info(prefer: dict, fallback: dict) -> dict:
    """Combina informações usando a base por nota como prioridade."""
    prefer = prefer or {}
    fallback = fallback or {}
    out = {}
    for k in ["vendedor", "gerente", "segmento", "razao_social", "cnpj", "contato", "origem"]:
        out[k] = normalize_text(prefer.get(k)) or normalize_text(fallback.get(k))
    return out


def _safe_amount(value) -> float:
    if value is None:
        return 0.0
    if isinstance(value, (int, float)):
        try:
            return abs(float(value))
        except Exception:
            return 0.0
    txt = normalize_text(value).replace("R$", "").replace(" ", "")
    if not txt:
        return 0.0
    # Trata 1.234,56 e 1234.56.
    if "," in txt:
        txt = txt.replace(".", "").replace(",", ".")
    try:
        return abs(float(txt))
    except Exception:
        return 0.0



def format_identifier(value, width: int = 0) -> str:
    """Mantém códigos como texto e recompõe zeros à esquerda quando numéricos."""
    txt = normalize_text(value)
    if not txt:
        return ""
    digits = re.sub(r"\D+", "", txt)
    if digits and len(digits) == len(re.sub(r"\s+", "", txt)):
        return digits.zfill(width) if width else digits
    if re.fullmatch(r"\d+", digits or "") and not re.search(r"[A-Za-z]", txt):
        return digits.zfill(width) if width else digits
    return txt.upper()


def normalize_parcela_key(value) -> str:
    txt = normalize_text(value)
    if not txt:
        return ""
    digits = re.sub(r"\D+", "", txt)
    if digits:
        return digits.lstrip("0") or "0"
    return normalize_col_key(txt)


def make_title_lookup_key(prefixo, numero, parcela, tipo) -> str:
    return "|".join([
        normalize_col_key(prefixo),
        normalize_note_key(numero),
        normalize_parcela_key(parcela),
        normalize_col_key(tipo),
    ])


def make_note_parcela_key(numero, parcela) -> str:
    return f"{normalize_note_key(numero)}|{normalize_parcela_key(parcela)}"


def build_relatorio_vendedor_maps(df_base: pd.DataFrame) -> tuple[dict, dict, dict]:
    """Mapeia o relatório de inadimplência por vendedor para completar cadastros.

    A chave mais segura é PRF + número + parcela + tipo. Como alternativa,
    utiliza número + parcela e, somente quando a nota é única, o número da nota.
    """
    if df_base.empty:
        return {}, {}, {}

    col_prefixo = find_col(df_base, ["PRF", "Prefixo", "Prefixo Titulo"])
    col_numero = find_col(df_base, ["NUMERO", "NÚMERO", "No. Titulo", "Título", "Titulo"])
    col_parcela = find_col(df_base, ["PARC", "Parcela"])
    col_tipo = find_col(df_base, ["TIPO", "TP", "Tipo"])
    col_cliente = find_col(df_base, ["CLIENTE", "Código Cliente", "Codigo Cliente", "Cod Cliente"])
    col_loja = find_col(df_base, ["LOJA", "Loja"])
    col_nome = find_col(df_base, ["NOME DO CLIENTE", "Nome Cliente", "Razão Social", "Razao Social", "Nome"])
    col_fantasia = find_col(df_base, ["N FANTASIA", "Nome Fantasia", "N. Fantasia", "Fantasia"])
    col_vendedor = find_col(df_base, ["VENDEDOR", "Nome Vendedor", "Vendedor / Representante"])
    col_gerente = find_col(df_base, ["GERENTE", "Gerente"])
    col_emissao = find_col(df_base, ["EMISSAO", "EMISSÃO", "Data de Emissao", "Data Emissão"])
    col_vencimento = find_col(df_base, ["VENCIMENTO", "Vencto Titulo", "Vencto. Título"])
    col_saldo_corrigido = find_col(df_base, ["SALDO CORR.", "SALDO CORR", "Saldo Corrigido", "Valor Corrigido"])
    col_banco_status = find_col(df_base, ["Bco St", "BCO ST", "Banco Status", "Status Banco"])
    col_tel_fin = find_col(df_base, ["Tel. Fin.", "Telefone Financeiro", "Tel Financeiro", "Fone Financeiro"])
    col_tel_com = find_col(df_base, ["Tel. Com.", "Telefone Comercial", "Tel Comercial", "Fone Comercial"])

    if not col_numero:
        return {}, {}, {}

    exact: dict[str, dict] = {}
    by_note_parcela: dict[str, dict] = {}
    note_values: dict[str, list[dict]] = defaultdict(list)

    for _, row in df_base.iterrows():
        numero = row.get(col_numero, "")
        note_key = normalize_note_key(numero)
        if not note_key:
            continue
        cliente_codigo = format_identifier(row.get(col_cliente, ""), 6) if col_cliente else ""
        loja = format_identifier(row.get(col_loja, ""), 2) if col_loja else ""
        nome = upper_text(row.get(col_nome, "")) if col_nome else ""
        fantasia = upper_text(row.get(col_fantasia, "")) if col_fantasia else ""
        info = {
            "cliente_codigo": cliente_codigo,
            "loja": loja,
            "razao_social": nome,
            "nome_fantasia": fantasia,
            "vendedor": canonical_vendor_display(row.get(col_vendedor, "")) if col_vendedor else "",
            "gerente": canonical_manager_display(row.get(col_gerente, "")) if col_gerente else "",
            "dt_emissao": to_date_str(row.get(col_emissao, "")) if col_emissao else "",
            "vencimento_titulo": to_date_str(row.get(col_vencimento, "")) if col_vencimento else "",
            "saldo_corrigido": _safe_amount(row.get(col_saldo_corrigido, 0)) if col_saldo_corrigido else 0.0,
            "banco_status": upper_text(row.get(col_banco_status, "")) if col_banco_status else "",
            "telefone_financeiro": upper_text(row.get(col_tel_fin, "")) if col_tel_fin else "",
            "telefone_comercial": upper_text(row.get(col_tel_com, "")) if col_tel_com else "",
            "origem": "RELATÓRIO POR VENDEDOR",
        }
        exact_key = make_title_lookup_key(
            row.get(col_prefixo, "") if col_prefixo else "",
            numero,
            row.get(col_parcela, "") if col_parcela else "",
            row.get(col_tipo, "") if col_tipo else "",
        )
        note_parcela_key = make_note_parcela_key(
            numero,
            row.get(col_parcela, "") if col_parcela else "",
        )
        exact.setdefault(exact_key, info)
        by_note_parcela.setdefault(note_parcela_key, info)
        note_values[note_key].append(info)

    unique_note: dict[str, dict] = {}
    for note_key, values in note_values.items():
        signatures = {
            (
                v.get("cliente_codigo", ""), v.get("loja", ""), v.get("razao_social", ""),
                v.get("vendedor", ""), v.get("gerente", "")
            )
            for v in values
        }
        if len(signatures) == 1:
            unique_note[note_key] = values[0]
    return exact, by_note_parcela, unique_note


def get_relatorio_vendedor_info_for(row, maps: tuple[dict, dict, dict]) -> dict:
    if not maps:
        return {}
    exact, by_note_parcela, unique_note = maps
    exact_key = make_title_lookup_key(
        row.get("Prefixo", row.get("prefixo", "")),
        row.get("No. Titulo", row.get("numero_titulo", "")),
        row.get("Parcela", row.get("parcela", "")),
        row.get("Tipo", row.get("tipo", "")),
    )
    note_parcela_key = make_note_parcela_key(
        row.get("No. Titulo", row.get("numero_titulo", "")),
        row.get("Parcela", row.get("parcela", "")),
    )
    note_key = normalize_note_key(row.get("No. Titulo", row.get("numero_titulo", "")))
    return exact.get(exact_key) or by_note_parcela.get(note_parcela_key) or unique_note.get(note_key) or {}


def load_relatorio_vendedor_maps() -> tuple[tuple[dict, dict, dict], str]:
    data, origem = find_relatorio_vendedor_bytes()
    if not data:
        return ({}, {}, {}), origem
    df_base = read_excel_any(data)
    maps = build_relatorio_vendedor_maps(df_base)
    mapped = len(maps[0]) if maps else 0
    return maps, f"{origem} • {len(df_base)} linha(s) • {mapped} título(s) mapeado(s)"



def _read_excel_with_flexible_header(file_bytes: bytes, required_terms: list[str]) -> pd.DataFrame:
    """Lê planilhas Protheus que trazem título na primeira linha e cabeçalho depois."""
    # Tentativa rápida usando a segunda linha como cabeçalho, padrão de muitos relatórios MATR.
    for header in [1, 0, 2, 3, 4, 5]:
        try:
            df = pd.read_excel(BytesIO(file_bytes), header=header)
            df.columns = [str(c).strip() for c in df.columns]
            keys = {normalize_col_key(c) for c in df.columns}
            if all(any(normalize_col_key(term) in k or k in normalize_col_key(term) for k in keys) for term in required_terms):
                return df.dropna(how="all")
        except Exception:
            pass
    # Fallback: encontra a linha que contém as colunas necessárias.
    raw = pd.read_excel(BytesIO(file_bytes), header=None)
    for i in range(min(25, len(raw))):
        row_vals = [normalize_col_key(x) for x in raw.iloc[i].tolist()]
        if all(normalize_col_key(term) in row_vals for term in required_terms):
            header = [str(x).strip() if str(x).strip() and str(x) != "nan" else f"Coluna_{j+1}" for j, x in enumerate(raw.iloc[i].tolist())]
            df = raw.iloc[i+1:].copy()
            df.columns = header
            return df.dropna(how="all")
    # Último fallback: leitor genérico já usado no app.
    return read_excel_any(file_bytes)


def find_cadastro_clientes_bytes() -> Tuple[Optional[bytes], str]:
    """Localiza o cadastro de clientes Protheus, preferencialmente MATR021.

    O arquivo pode ficar na raiz do repositório ou em dados/ com nomes como:
    matr021.xlsx, MATR021.xlsx, cadastro_clientes.xlsx ou clientes.xlsx.
    """
    local_candidates = [
        Path("matr021.xlsx"), Path("MATR021.xlsx"), Path("cadastro_clientes.xlsx"), Path("clientes.xlsx"),
        Path("dados/matr021.xlsx"), Path("dados/MATR021.xlsx"), Path("dados/cadastro_clientes.xlsx"), Path("dados/clientes.xlsx"),
    ]
    for cand in local_candidates:
        if cand.exists() and cand.is_file():
            data = cand.read_bytes()
            if len(data) >= 200:
                return data, f"Cadastro de clientes local: {cand.as_posix()}"

    configured = get_config("cadastro_clientes_github", "").strip() if DB_PATH.exists() else ""
    if configured:
        if configured.lower().startswith(("http://", "https://")):
            try:
                with urlopen(configured, timeout=35) as response:
                    data = response.read()
                if len(data) >= 200:
                    return data, "Cadastro de clientes carregado pela URL configurada"
            except Exception as exc:
                return None, f"Erro ao ler cadastro de clientes configurado: {exc}"
        data, msg = github_get_file_bytes(configured)
        if data and len(data) >= 200:
            return data, msg

    github_candidates = [
        "matr021.xlsx", "MATR021.xlsx", "cadastro_clientes.xlsx", "clientes.xlsx",
        "dados/matr021.xlsx", "dados/MATR021.xlsx", "dados/cadastro_clientes.xlsx", "dados/clientes.xlsx",
    ]
    for cand in github_candidates:
        data, msg = github_get_file_bytes(cand)
        if data and len(data) >= 200:
            return data, msg

    # Também procura automaticamente por nomes que contenham matr021 ou clientes.
    paths = github_list_file_paths("") + github_list_file_paths("dados")
    for p in paths:
        key = _file_name_key(p)
        if p.lower().endswith((".xlsx", ".xls")) and ("matr021" in key or "clientes" in key or "cadastroclientes" in key):
            data, msg = github_get_file_bytes(p)
            if data and len(data) >= 200:
                return data, msg
    return None, "Cadastro de clientes não encontrado. Envie matr021.xlsx na raiz do repositório ou na pasta dados/."


def build_cadastro_clientes_maps(df_cli: pd.DataFrame) -> tuple[dict, dict]:
    """Monta mapas do MATR021 por código+loja e por nome do cliente."""
    if df_cli.empty:
        return {}, {}
    col_codigo = find_col(df_cli, ["Codigo", "Código", "Cod Cliente", "Código Cliente", "Cliente"])
    col_loja = find_col(df_cli, ["Loja", "Loja Cliente", "A1_LOJA"])
    col_nome = find_col(df_cli, ["Nome", "Razão Social", "Razao Social", "Nome Cliente", "A1_NOME"])
    col_cnpj = find_col(df_cli, ["CNPJ/CPF", "CNPJ", "CPF/CNPJ", "A1_CGC"])
    col_fantasia = find_col(df_cli, ["N Fantasia", "Nome Fantasia", "N. Fantasia", "Fantasia", "A1_NREDUZ"])
    col_endereco = find_col(df_cli, ["Endereco", "Endereço", "Endereço Cliente", "A1_END"])
    col_bairro = find_col(df_cli, ["Bairro", "A1_BAIRRO"])
    col_municipio = find_col(df_cli, ["Municipio", "Município", "Cidade", "A1_MUN"])
    col_uf = find_col(df_cli, ["Estado", "UF", "A1_EST"])
    col_cep = find_col(df_cli, ["CEP", "Cep", "A1_CEP"])
    col_contato = find_col(df_cli, ["Contato", "Contato Financeiro", "Dept Contato", "Responsável", "Responsavel"])
    col_tel_fin = find_col(df_cli, ["Tel. Fin.", "Tel Fin", "Telefone Financeiro", "Fone Financeiro"])
    col_tel_com = find_col(df_cli, ["Tel. Com.", "Tel Com", "Telefone Comercial", "Tel. Fat", "Telefone", "Tel. Fat."])
    col_email_nfe = find_col(df_cli, ["E-Mail NFe", "Email NFe", "E-mail NFe", "E-Mail Nf-e"])
    col_email_com = find_col(df_cli, ["E-Mail Com", "Email Comercial", "E-mail Comercial", "E-Mail"])
    col_email_fin = find_col(df_cli, ["E-Mail Fin", "Email Financeiro", "E-mail Financeiro"])

    by_codigo_loja: dict[str, dict] = {}
    by_nome: dict[str, dict] = {}
    for _, r in df_cli.iterrows():
        codigo = format_identifier(r.get(col_codigo, "") if col_codigo else "", 6)
        loja = format_identifier(r.get(col_loja, "") if col_loja else "", 2)
        nome = upper_text(r.get(col_nome, "") if col_nome else "")
        if not (codigo or nome):
            continue
        info = {
            "cliente_codigo": codigo,
            "loja": loja,
            "razao_social": nome,
            "nome_cliente": nome,
            "nome_fantasia": upper_text(r.get(col_fantasia, "") if col_fantasia else ""),
            "cnpj": upper_text(r.get(col_cnpj, "") if col_cnpj else ""),
            "contato": upper_text(r.get(col_contato, "") if col_contato else ""),
            "telefone_financeiro": upper_text(r.get(col_tel_fin, "") if col_tel_fin else ""),
            "telefone_comercial": upper_text(r.get(col_tel_com, "") if col_tel_com else ""),
            "endereco": upper_text(r.get(col_endereco, "") if col_endereco else ""),
            "bairro": upper_text(r.get(col_bairro, "") if col_bairro else ""),
            "municipio": upper_text(r.get(col_municipio, "") if col_municipio else ""),
            "uf": upper_text(r.get(col_uf, "") if col_uf else ""),
            "cep": upper_text(r.get(col_cep, "") if col_cep else ""),
            "email_nfe": upper_text(r.get(col_email_nfe, "") if col_email_nfe else ""),
            "email_comercial": upper_text(r.get(col_email_com, "") if col_email_com else ""),
            "email_financeiro": upper_text(r.get(col_email_fin, "") if col_email_fin else ""),
            "origem": "MATR021",
        }
        if codigo and loja:
            by_codigo_loja[f"{codigo}|{loja}".upper()] = info
        if nome:
            key = normalize_col_key(nome)
            current = by_nome.get(key)
            score = sum(bool(normalize_text(info.get(c, ""))) for c in ["cnpj", "nome_fantasia", "telefone_financeiro", "telefone_comercial", "endereco", "email_financeiro"])
            old_score = sum(bool(normalize_text((current or {}).get(c, ""))) for c in ["cnpj", "nome_fantasia", "telefone_financeiro", "telefone_comercial", "endereco", "email_financeiro"])
            if current is None or score >= old_score:
                by_nome[key] = info
    return by_codigo_loja, by_nome


def load_cadastro_clientes_maps() -> tuple[tuple[dict, dict], str]:
    data, origem = find_cadastro_clientes_bytes()
    if not data:
        return ({}, {}), origem
    df_cli = _read_excel_with_flexible_header(data, ["Codigo", "Loja", "Nome"])
    maps = build_cadastro_clientes_maps(df_cli)
    qtd = len(maps[0]) if maps else 0
    return maps, f"{origem} • {len(df_cli)} linha(s) • {qtd} cliente(s) mapeado(s)"


def get_cadastro_cliente_info_for(row, maps: tuple[dict, dict]) -> dict:
    if not maps:
        return {}
    by_codigo_loja, by_nome = maps
    codigo = format_identifier(row.get("Cliente", row.get("cliente_codigo", "")), 6)
    loja = format_identifier(row.get("Loja", row.get("loja", "")), 2)
    nome = upper_text(row.get("Nome Cliente", row.get("nome_cliente", "")))
    return by_codigo_loja.get(f"{codigo}|{loja}".upper()) or by_nome.get(normalize_col_key(nome)) or {}

def build_faturamento_maps(df_base: pd.DataFrame) -> tuple[dict, dict, dict, dict]:
    """Cria mapas da BASE BI com uma única combinação por NF/segmento.

    Regras:
    - A NF é a chave principal.
    - Dentro da NF, os itens são consolidados por SEGMENTO.
    - Se a NF tiver mais de um segmento, prevalece o segmento de maior valor.
    - Dentro do segmento vencedor, prevalece uma única dupla vendedor/gerente.
    - Variações de nome do vendedor (pontuação, LT/LTDA) são unificadas.
    - Dados comerciais nunca são herdados de outra NF do mesmo cliente.
    """
    if df_base.empty:
        return {}, {}, {}, {}

    df_base = normalize_faturamento_base_columns(df_base)
    layout_rfateqp = False

    col_nota = find_col(df_base, [
        "Nota Fiscal", "NF", "N.F.", "Nº NF", "No NF", "Número NF", "Numero NF",
        "Nota", "Documento", "No. Titulo", "Nº Título", "Titulo", "Título",
        "Numero", "Número", "Pedido", "Nro Pedido", "Nº Pedido"
    ])
    col_cliente = find_col(df_base, ["CLIENTE", "Cliente", "Cod Cliente", "Código Cliente", "Cod. Cliente", "A1_COD", "Codigo", "Código"])
    col_loja = find_col(df_base, ["Loja", "A1_LOJA"])
    col_nome = find_col(df_base, ["NOME DO CLIENTE", "Nome Cliente", "Cliente Nome", "Nome", "Nome Fantasia", "A1_NOME"])
    col_razao = find_col(df_base, ["Razão Social", "Razao Social", "NOME DO CLIENTE", "Nome Cliente", "A1_NREDUZ"])
    col_cnpj = find_col(df_base, ["CNPJ", "CPF/CNPJ", "CNPJ/CPF", "A1_CGC", "CGC"])
    col_contato = find_col(df_base, ["Contato", "Responsável", "Responsavel", "Contato Financeiro", "Email", "E-mail", "Telefone"])
    col_vendedor = find_col(df_base, [
        "VENDEDOR / REPRESENTANTE", "Nome Vendedor", "Nome do Vendedor",
        "Vendedor Representante", "Representante", "Consultor Comercial",
        "VENDEDOR", "Vendedor", "Consultor", "Comercial"
    ])
    col_gerente = find_col(df_base, ["GERENTE", "Gerente", "Gerente Comercial", "Supervisor", "Coordenador"])
    col_segmento = find_col(df_base, ["SEGMENTO", "Segmento", "Segmento Comercial", "Linha/Segmento", "SEGMENTO - 1"])
    col_valor = find_col(df_base, ["VALOR BRUTO", "VALOR", "Valor Bruto", "Valor", "VALOR ", "Vlr.Total", "Valor Total"])

    # Primeiro identifica uma grafia preferencial para cada vendedor equivalente.
    vendor_variants: dict[str, Counter] = defaultdict(Counter)
    for _, r in df_base.iterrows():
        raw = normalize_text(r.get(col_vendedor, "")) if col_vendedor else ""
        key = canonical_vendor_key(raw)
        if key:
            vendor_variants[key][canonical_vendor_display(raw)] += 1

    preferred_vendor: dict[str, str] = {}
    for key, counts in vendor_variants.items():
        # A grafia mais longa resolve LT x LTDA; frequência funciona como desempate.
        preferred_vendor[key] = max(counts.keys(), key=lambda v: (len(v), counts[v]))

    # Consolida por NF + segmento e, dentro do grupo, por dupla vendedor/gerente.
    groups: dict[tuple[str, str], dict] = {}
    note_groups: dict[str, list[tuple[str, str]]] = defaultdict(list)
    by_cliente_loja, by_cliente, by_nome = {}, {}, {}

    for _, r in df_base.iterrows():
        nota_key = normalize_note_key(r.get(col_nota, "")) if col_nota else ""
        segmento = canonical_segment_display(r.get(col_segmento, "")) if col_segmento else ""
        segmento = segmento or "SEM SEGMENTO"
        vendedor_raw = normalize_text(r.get(col_vendedor, "")) if col_vendedor else ""
        vendedor_key = canonical_vendor_key(vendedor_raw)
        vendedor = preferred_vendor.get(vendedor_key, canonical_vendor_display(vendedor_raw))
        gerente = canonical_manager_display(r.get(col_gerente, "")) if col_gerente else ""
        amount = _safe_amount(r.get(col_valor, 0)) if col_valor else 0.0
        # Quando o valor não estiver preenchido, cada linha vale 1 para o critério de desempate.
        weight = amount if amount > 0 else 1.0

        general = {
            "vendedor": vendedor,
            "gerente": gerente,
            "segmento": segmento,
            "razao_social": normalize_text(r.get(col_razao, "")) if col_razao else "",
            "cnpj": normalize_text(r.get(col_cnpj, "")) if col_cnpj else "",
            "contato": normalize_text(r.get(col_contato, "")) if col_contato else "",
            "origem": "BASE BI",
        }

        if nota_key:
            gkey = (nota_key, normalize_col_key(segmento))
            if gkey not in groups:
                groups[gkey] = {
                    "nota": nota_key,
                    "segmento": segmento,
                    "total_value": 0.0,
                    "rows": 0,
                    "pair_value": defaultdict(float),
                    "pair_count": Counter(),
                    "general": general.copy(),
                }
                note_groups[nota_key].append(gkey)
            g = groups[gkey]
            pair = (vendedor, gerente)
            g["total_value"] += weight
            g["rows"] += 1
            g["pair_value"][pair] += weight
            g["pair_count"][pair] += 1
            # Preenche dados gerais que porventura estavam vazios na primeira linha.
            for fld in ["razao_social", "cnpj", "contato"]:
                if not g["general"].get(fld) and general.get(fld):
                    g["general"][fld] = general[fld]

        # Fallback apenas para dados cadastrais. Vendedor/gerente/segmento ficam vazios
        # para impedir que uma NF herde responsáveis de outra NF do mesmo cliente.
        cadastro_info = {
            "vendedor": "", "gerente": "", "segmento": "",
            "razao_social": general.get("razao_social", ""),
            "cnpj": general.get("cnpj", ""),
            "contato": general.get("contato", ""),
            "origem": "BASE BI",
        }
        cliente = normalize_text(r.get(col_cliente, "")) if col_cliente else ""
        loja = normalize_text(r.get(col_loja, "")) if col_loja else ""
        nome = normalize_text(r.get(col_nome, "")) if col_nome else ""
        if cliente and loja and f"{cliente}|{loja}".upper() not in by_cliente_loja:
            by_cliente_loja[f"{cliente}|{loja}".upper()] = cadastro_info
        if cliente and cliente.upper() not in by_cliente:
            by_cliente[cliente.upper()] = cadastro_info
        if nome and normalize_col_key(nome) not in by_nome:
            by_nome[normalize_col_key(nome)] = cadastro_info
        cnpj = _digits(cadastro_info.get("cnpj"))
        if cnpj and f"CNPJ:{cnpj}" not in by_nome:
            by_nome[f"CNPJ:{cnpj}"] = cadastro_info

    by_nota = {}
    for nota_key, gkeys in note_groups.items():
        candidates = []
        for gkey in gkeys:
            g = groups[gkey]
            pair = max(
                g["pair_value"].keys(),
                key=lambda p: (g["pair_value"][p], g["pair_count"][p], bool(p[1]), bool(p[0]))
            ) if g["pair_value"] else ("", "")
            info = g["general"].copy()
            info["vendedor"], info["gerente"] = pair
            info["segmento"] = g["segmento"]
            candidates.append((g["total_value"], g["rows"], info))
        # Um único segmento/responsável por NF: maior valor, depois maior quantidade de linhas.
        candidates.sort(key=lambda x: (x[0], x[1]), reverse=True)
        by_nota[nota_key] = candidates[0][2]

    return by_nota, by_cliente_loja, by_cliente, by_nome


def get_faturamento_info_for(row, maps: tuple) -> dict:
    if not maps:
        return {}
    if len(maps) == 4:
        by_nota, by_cliente_loja, by_cliente, by_nome = maps
    else:
        by_cliente_loja, by_cliente, by_nome = maps
        by_nota = {}
    nota_key = normalize_note_key(row.get("No. Titulo"))
    cliente = normalize_text(row.get("Cliente"))
    loja = normalize_text(row.get("Loja"))
    nome = normalize_text(row.get("Nome Cliente"))
    note_info = by_nota.get(nota_key) or {}
    fallback = (
        by_cliente_loja.get(f"{cliente}|{loja}".upper())
        or by_cliente.get(cliente.upper())
        or by_nome.get(normalize_col_key(nome))
        or {}
    )
    return choose_info(note_info, fallback)


def load_faturamento_maps_from_github() -> tuple[tuple[dict, dict, dict, dict], str]:
    """Carrega a BASE BI automaticamente e cria o mapa Nota Fiscal -> vendedor/gerente.

    Não depende mais de URL raw: procura BASE BI.xlsx na raiz ou em dados/ do repositório.
    """
    data, origem = find_base_bi_bytes()
    if not data:
        return ({}, {}, {}, {}), origem
    df_base = read_excel_any(data)
    maps = build_faturamento_maps(df_base)
    notas = len(maps[0]) if maps else 0
    return maps, f"{origem} • BASE BI anterior • {len(df_base)} linha(s) • {notas} nota(s) mapeada(s)"


def parse_legacy_prf_numero(value) -> tuple[str, str, str]:
    """Extrai prefixo, número e parcela de campos como AFI-013998 ou 003-000016843-001."""
    txt = normalize_text(value).upper()
    if not txt:
        return "", "", ""
    parts = [x for x in re.split(r"[-\s]+", txt) if x]
    nums = re.findall(r"\d+", txt)
    prefixo = parts[0] if parts else ""
    numero = ""
    parcela = ""
    if len(nums) >= 3 and len(nums[-1]) <= 3:
        numero = nums[-2]
        parcela = nums[-1]
    elif nums:
        numero = nums[-1]
    return prefixo, numero, parcela


def parse_legacy_cliente(value) -> tuple[str, str, str]:
    """Lê campos no padrão Codigo-Lj-Nome do Cliente."""
    txt = normalize_text(value)
    m = re.match(r"^\s*(\d+)\s*-\s*([\w\d]+)\s*-\s*(.+)$", txt)
    if m:
        return m.group(1).strip(), m.group(2).strip(), m.group(3).strip()
    return "", "", txt


def read_legacy_history_upload(file) -> pd.DataFrame:
    """Lê a planilha antiga de tomada de decisão e transforma em histórico por bloco de cliente.

    A planilha antiga costuma quebrar o texto do histórico em várias linhas do mesmo cliente.
    Por isso o app consolida o texto do bloco e aplica o histórico completo aos títulos/Notas
    encontrados naquele cliente.
    """
    file_bytes = file.read() if hasattr(file, "read") else bytes(file)
    try:
        raw = pd.read_excel(BytesIO(file_bytes))
    except Exception:
        raw = _xlsx_fallback_to_dataframe(file_bytes)

    raw.columns = [str(c).strip() for c in raw.columns]
    if raw.empty:
        raise ValueError("A planilha de histórico está vazia.")

    code_col = next((c for c in raw.columns if "Codigo" in c or "Código" in c), raw.columns[0])
    prf_col = next((c for c in raw.columns if "Prf" in c or "Numero" in c or "Número" in c), raw.columns[1] if len(raw.columns) > 1 else raw.columns[0])
    hist_col = next((c for c in raw.columns if "HIST" in c.upper()), None)
    if hist_col is None:
        raise ValueError("Não encontrei a coluna HISTÓRICO na planilha.")

    # Importamos somente a coluna HISTÓRICO.
    # As demais colunas da planilha antiga costumam trazer datas/status e geravam texto confuso.
    extra_cols = []

    blocks = []
    current = None

    def flush():
        nonlocal current
        if not current:
            return
        hist_lines = [h for h in current.get("hist_lines", []) if h]
        note_keys = sorted(set([k for k in current.get("note_keys", []) if k]))
        if hist_lines and note_keys:
            hist = " ".join(hist_lines)
            hist = clean_history_text(hist)
            if not hist:
                current = None
                return
            blocks.append({
                "cliente_codigo": current.get("cliente_codigo", ""),
                "loja": current.get("loja", ""),
                "nome_cliente": current.get("nome_cliente", ""),
                "notas": ", ".join(note_keys),
                "historico_legado": hist,
                "qtd_notas_planilha": len(note_keys),
            })
        current = None

    for _, row in raw.iterrows():
        code_val = normalize_text(row.get(code_col))
        prf_val = normalize_text(row.get(prf_col))
        hist_val = normalize_text(row.get(hist_col))

        # Ignora cabeçalhos repetidos e linhas totalmente vazias.
        if not code_val and not prf_val and not hist_val:
            flush()
            continue
        if "Codigo" in code_val and ("Nome" in code_val or "Cliente" in code_val):
            flush()
            continue

        # Linhas totalizadoras não possuem número do título; elas encerram o bloco.
        if not prf_val:
            flush()
            continue

        cliente_codigo, loja, nome_cliente = parse_legacy_cliente(code_val)
        _, numero, parcela = parse_legacy_prf_numero(prf_val)
        note_key = normalize_note_key(numero or prf_val)
        cid = make_cliente_id(cliente_codigo, loja, nome_cliente)

        if current is None or current.get("cliente_id") != cid:
            flush()
            current = {
                "cliente_id": cid,
                "cliente_codigo": cliente_codigo,
                "loja": loja,
                "nome_cliente": nome_cliente,
                "note_keys": [],
                "hist_lines": [],
            }

        if note_key:
            current["note_keys"].append(note_key)

        if hist_val:
            hist_limpo = clean_history_text(hist_val)
            if hist_limpo:
                current["hist_lines"].append(hist_limpo)

        for c in extra_cols:
            extra = normalize_text(row.get(c))
            if extra and not re.fullmatch(r"[\d.,]+", extra) and extra.upper() not in {"NAN", "NONE"}:
                # Evita repetir colunas que são claramente dados financeiros/datas.
                if extra.upper() not in hist_val.upper():
                    current["hist_lines"].append(f"Decisão/status: {extra}")

    flush()
    out = pd.DataFrame(blocks)
    if out.empty:
        raise ValueError("Não encontrei histórico aproveitável na planilha enviada.")
    return out


def import_legacy_history(df_legacy: pd.DataFrame, data_ref: date, responsavel: str = "Importação legado", atualizar_observacao: bool = True) -> dict:
    """Importa histórico legado casando por número da nota/título."""
    backup_db("antes_historico_legado")
    conn = get_conn()
    try:
        cur = conn.cursor()
        now = datetime.now().isoformat(timespec="seconds")
        data_ref_str = data_ref.isoformat()
        tit = pd.read_sql_query("SELECT titulo_id, cliente_codigo, loja, nome_cliente, numero_titulo, observacao_atual FROM titulos", conn)
        if tit.empty:
            raise ValueError("Ainda não existe base de títulos no CRM. Faça primeiro o upload diário do Protheus.")
        tit["nota_key"] = tit["numero_titulo"].apply(normalize_note_key)
        tit["cliente_codigo_norm"] = tit["cliente_codigo"].apply(normalize_text)

        inseridos = 0
        titulos_afetados = set()
        sem_match = []

        for _, rec in df_legacy.iterrows():
            notas = [n.strip() for n in str(rec.get("notas", "")).split(",") if n.strip()]
            cliente_codigo = normalize_text(rec.get("cliente_codigo"))
            historico = clean_history_text(rec.get("historico_legado"))
            nome_cliente = normalize_text(rec.get("nome_cliente"))
            if not notas or not historico:
                continue

            mask = tit["nota_key"].isin(notas)
            if cliente_codigo:
                mask_cliente = tit["cliente_codigo_norm"].eq(cliente_codigo)
                matched = tit[mask & mask_cliente].copy()
                if matched.empty:
                    matched = tit[mask].copy()
            else:
                matched = tit[mask].copy()

            if matched.empty:
                sem_match.append(f"{nome_cliente or cliente_codigo}: {', '.join(notas)}")
                continue

            for _, t in matched.iterrows():
                tid = str(t["titulo_id"])
                obs = f"Histórico legado importado: {historico}"
                exists = cur.execute(
                    """
                    SELECT 1 FROM historico_acoes
                     WHERE titulo_id = ? AND tipo_acao = ? AND observacao = ?
                     LIMIT 1
                    """,
                    (tid, "Histórico legado", obs),
                ).fetchone()
                if exists:
                    continue
                cur.execute(
                    """
                    INSERT INTO historico_acoes (titulo_id, data_acao, tipo_acao, responsavel, observacao, created_at)
                    VALUES (?, ?, ?, ?, ?, ?)
                    """,
                    (tid, data_ref_str, "Histórico legado", upper_text(responsavel), obs, now),
                )
                if atualizar_observacao and not normalize_text(t.get("observacao_atual")):
                    cur.execute(
                        "UPDATE titulos SET observacao_atual = ?, updated_at = ? WHERE titulo_id = ?",
                        (historico[:1500], now, tid),
                    )
                inseridos += 1
                titulos_afetados.add(tid)

        conn.commit()
        return {
            "historicos_inseridos": inseridos,
            "titulos_afetados": len(titulos_afetados),
            "blocos_lidos": len(df_legacy),
            "sem_match": sem_match[:50],
            "sem_match_total": len(sem_match),
        }
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()



