def data_extenso_pt(dt: date) -> str:
    meses = [
        "janeiro", "fevereiro", "março", "abril", "maio", "junho",
        "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"
    ]
    return f"{dt.day:02d} de {meses[dt.month - 1]} de {dt.year}"


def safe_filename(texto: str) -> str:
    txt = normalize_text(texto).lower()
    txt = re.sub(r"[áàãâä]", "a", txt)
    txt = re.sub(r"[éèêë]", "e", txt)
    txt = re.sub(r"[íìîï]", "i", txt)
    txt = re.sub(r"[óòõôö]", "o", txt)
    txt = re.sub(r"[úùûü]", "u", txt)
    txt = re.sub(r"ç", "c", txt)
    txt = re.sub(r"[^a-z0-9]+", "_", txt).strip("_")
    return txt[:80] or "cliente"


def _titulo_label_for_notificacao(row: pd.Series) -> str:
    prefixo = upper_text(row.get("prefixo"))
    numero = format_identifier(row.get("numero_titulo"), 6)
    parcela = _display_parcela(row.get("parcela"))
    if prefixo and parcela:
        return f"{prefixo}-{numero}/{parcela}"
    if prefixo:
        return f"{prefixo}-{numero}"
    if parcela:
        return f"{numero}/{parcela}"
    return numero


def _valor_notificacao(row: pd.Series) -> float:
    try:
        corrigido = float(row.get("saldo_corrigido") or 0)
    except Exception:
        corrigido = 0.0
    if corrigido > 0:
        return corrigido
    try:
        return float(row.get("saldo_atual") or 0) + float(row.get("multa") or 0) + float(row.get("juros") or 0)
    except Exception:
        return 0.0


def montar_endereco_completo_cliente(row) -> str:
    """Monta endereço completo do cliente para uso na notificação."""
    try:
        endereco = normalize_text(row.get("endereco", "") or "").strip()
        bairro = normalize_text(row.get("bairro", "") or "").strip()
        municipio = normalize_text(row.get("municipio", "") or "").strip()
        uf = normalize_text(row.get("uf", "") or "").strip()
        cep = normalize_text(row.get("cep", "") or "").strip()
    except Exception:
        endereco = bairro = municipio = uf = cep = ""

    partes = []
    if endereco:
        partes.append(endereco)
    if bairro:
        partes.append(f"Bairro: {bairro}")

    cidade_uf = ""
    if municipio and uf:
        cidade_uf = f"{municipio}/{uf}"
    elif municipio:
        cidade_uf = municipio
    elif uf:
        cidade_uf = uf
    if cidade_uf:
        partes.append(cidade_uf)

    if cep:
        partes.append(f"CEP: {cep}")

    return " - ".join(partes)


def gerar_notificacao_extrajudicial_pdf(
    cliente_nome: str,
    razao_social: str,
    cnpj: str,
    endereco_cliente: str,
    titulos_cliente: pd.DataFrame,
    data_notificacao: date,
    data_contrato_txt: str = "",
    contraprestacao_txt: str = "",
    prazo_txt: str = "",
    signatario_txt: str = "Tiago Esteves da Cunha\nOAB/SP nº 266.999",
    teams_link: str = "",
) -> bytes:
    """Gera a notificação extrajudicial usando o PDF oficial como timbrado.

    Mantém o timbrado e o texto-base do modelo. Os títulos voltaram a sair em
    texto corrido, como no documento original, e em sequência de vencimento.
    O conteúdo é redesenhado sobre o timbrado com margem de segurança para não
    cortar o logotipo do escritório.
    """
    try:
        from copy import deepcopy
        from reportlab.lib import colors
        from reportlab.lib.enums import TA_JUSTIFY, TA_LEFT, TA_CENTER
        from reportlab.lib.styles import ParagraphStyle
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer
        from reportlab.graphics.barcode import qr
        from reportlab.graphics.shapes import Drawing
        from reportlab.graphics import renderPDF
        from pypdf import PdfReader, PdfWriter
    except Exception as exc:
        raise RuntimeError("Inclua reportlab>=4.0.0 e pypdf>=4.0.0 no requirements.txt.") from exc

    destinatario = normalize_text(razao_social or cliente_nome).strip() or normalize_text(cliente_nome or "CLIENTE")
    localidade = normalize_text(endereco_cliente).strip()
    cnpj_txt = normalize_text(cnpj).strip()
    data_contrato_txt = normalize_text(data_contrato_txt).strip() or "____/____/________"
    contraprestacao_txt = normalize_text(contraprestacao_txt).strip() or "R$ __________"
    prazo_txt = normalize_text(prazo_txt).strip()
    teams_link = str(teams_link or "").strip()

    titulos_df = titulos_cliente.copy() if titulos_cliente is not None else pd.DataFrame()
    if titulos_df.empty:
        titulos_lista = "títulos em aberto"
        vencimentos_lista = "datas constantes no demonstrativo de cobrança"
        valor_total = 0.0
    else:
        def _venc_date_for_sort(v):
            dt = parse_iso_date(normalize_text(v))
            return dt if dt else date.max

        titulos_df["_label"] = titulos_df.apply(_titulo_label_for_notificacao, axis=1)
        titulos_df["_valor_notif"] = titulos_df.apply(_valor_notificacao, axis=1)
        titulos_df["_venc_date_sort"] = titulos_df.get("vencimento", pd.Series(dtype=str)).apply(_venc_date_for_sort)
        titulos_df["_venc_fmt"] = titulos_df["_venc_date_sort"].apply(
            lambda dt: dt.strftime("%d/%m/%Y") if dt and dt != date.max else "sem data informada"
        )
        titulos_df = titulos_df.sort_values(by=["_venc_date_sort", "_label"], kind="stable")
        valor_total = float(titulos_df["_valor_notif"].sum())

        # Texto corrido no mesmo espírito do modelo: títulos em sequência e vencimentos na mesma ordem.
        titulos_lista = ", ".join(titulos_df["_label"].astype(str).tolist()) or "títulos em aberto"
        vencimentos_lista = ", ".join(titulos_df["_venc_fmt"].astype(str).tolist()) or "datas constantes no demonstrativo de cobrança"

    prazo_frase = f" no prazo de <b>{html.escape(prazo_txt)}</b>" if prazo_txt else ""

    modelo_bytes = base64.b64decode(NOTIFICACAO_MODELO_OFICIAL_B64)
    modelo_pdf = PdfReader(BytesIO(modelo_bytes))
    base_page = modelo_pdf.pages[0]
    width = float(base_page.mediabox.width)
    height = float(base_page.mediabox.height)

    buffer = BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=(width, height),
        leftMargin=70,
        rightMargin=70,
        topMargin=138,
        bottomMargin=125,
    )

    normal = ParagraphStyle(
        "NotifNormal",
        fontName="Times-Roman",
        fontSize=10.8,
        leading=18,
        alignment=TA_JUSTIFY,
        firstLineIndent=0,
        spaceAfter=0,
    )
    body = ParagraphStyle("NotifBody", parent=normal, firstLineIndent=112, leading=19)
    body_no_indent = ParagraphStyle("NotifBodyNoIndent", parent=normal, firstLineIndent=0, leading=19, alignment=TA_LEFT)
    bold = ParagraphStyle("NotifBold", parent=normal, fontName="Times-Bold", fontSize=10.8, leading=16, alignment=TA_LEFT)
    ref = ParagraphStyle("NotifRef", parent=normal, fontName="Times-Bold", fontSize=12, leading=15, alignment=TA_LEFT)
    sign = ParagraphStyle("NotifSign", parent=normal, fontName="Times-Roman", fontSize=10.5, leading=15, alignment=TA_CENTER)

    story = []
    story.append(Paragraph("À", bold))
    story.append(Spacer(1, 4))
    story.append(Paragraph(html.escape(destinatario), bold))
    if cnpj_txt:
        story.append(Paragraph(f"CNPJ: {html.escape(cnpj_txt)}", bold))
    if localidade:
        story.append(Paragraph(html.escape(localidade), bold))
    story.append(Spacer(1, 12))
    story.append(Paragraph("Ref. NOTIFICAÇÃO EXTRAJUDICIAL POR INADIMPLÊNCIA - PRAZO", ref))
    story.append(Spacer(1, 18))
    story.append(Paragraph("Prezados,", normal))
    story.append(Spacer(1, 10))

    p1 = (
        "A <b>First Medical</b> foi contratada para a prestação de serviços de locação de "
        f"equipamentos médicos em <b>{html.escape(data_contrato_txt)}</b> mediante a contraprestação mensal de "
        f"<b>{html.escape(contraprestacao_txt)}</b>."
    )
    story.append(Paragraph(p1, body))
    story.append(Spacer(1, 12))

    p2 = (
        "Ocorre que segundo informações da instituição bancária responsável pelo recebimento, consta o não "
        f"pagamento dos títulos <b>{html.escape(titulos_lista)}</b> vencidos em "
        f"<b>{html.escape(vencimentos_lista)}</b> totalizando o valor de "
        f"<b>{html.escape(br_money(valor_total))}</b>."
    )
    story.append(Paragraph(p2, body))
    story.append(Spacer(1, 12))

    p3 = (
        f"Assim, com o objetivo de constituir a <b>{html.escape(destinatario)}</b> em mora por inadimplência "
        "para fins de cobrança, execução ou falência, serve a presente como derradeira oportunidade de "
        "negociação pacífica do débito através do Termo de Confissão de Dívida e Parcelamento."
    )
    story.append(Paragraph(p3, body))
    story.append(Spacer(1, 12))

    p4 = (
        f"Diante do exposto, fica a <b>{html.escape(destinatario)}</b> Notificada Extrajudicialmente nos termos "
        "do art. 726 do Código de Processo Civil para que realize o pagamento ou transacione o débito"
        f"{prazo_frase} sob pena de rescisão contratual, remoção de equipamentos e adoção das medidas judiciais "
        "que o caso requer."
    )
    story.append(Paragraph(p4, body))
    story.append(Spacer(1, 24))
    story.append(Paragraph(f"São Paulo, {data_extenso_pt(data_notificacao)}.", body_no_indent))
    story.append(Spacer(1, 28))

    linhas_assinatura = [normalize_text(x) for x in normalize_text(signatario_txt).split("\n") if normalize_text(x)]
    if not linhas_assinatura:
        linhas_assinatura = ["Tiago Esteves da Cunha", "OAB/SP nº 266.999"]
    for linha in linhas_assinatura[:4]:
        story.append(Paragraph(html.escape(linha), sign))

    def draw_background(canv, _doc):
        canv.saveState()
        # Limpa a área do texto variável do modelo sem avançar sobre o logotipo.
        # A limpeza principal preserva o cabeçalho do escritório; a limpeza estreita
        # no canto esquerdo remove apenas o "À" original do PDF, evitando duplicidade
        # com o "À" preenchido pelo app.
        canv.setFillColor(colors.white)
        canv.rect(48, 82, width - 96, 650, stroke=0, fill=1)
        canv.rect(45, 718, 125, 58, stroke=0, fill=1)

        if teams_link and canv.getPageNumber() == 1:
            try:
                qr_widget = qr.QrCodeWidget(teams_link)
                bounds = qr_widget.getBounds()
                qr_size = 74
                w = bounds[2] - bounds[0]
                h = bounds[3] - bounds[1]
                drawing = Drawing(qr_size, qr_size, transform=[qr_size / w, 0, 0, qr_size / h, 0, 0])
                drawing.add(qr_widget)
                x_qr = width - 132
                y_qr = 96
                renderPDF.draw(drawing, canv, x_qr, y_qr)
            except Exception:
                pass
        canv.restoreState()

    doc.build(story, onFirstPage=draw_background, onLaterPages=draw_background)
    buffer.seek(0)
    overlay_pdf = PdfReader(buffer)
    writer = PdfWriter()
    for page in overlay_pdf.pages:
        merged = deepcopy(base_page)
        merged.merge_page(page)
        writer.add_page(merged)
    final_buffer = BytesIO()
    writer.write(final_buffer)
    final_buffer.seek(0)
    return final_buffer.getvalue()

