def load_regua() -> pd.DataFrame:
    conn = get_conn()
    df = pd.read_sql_query("SELECT * FROM regua_cobranca ORDER BY dia", conn)
    conn.close()
    return df


def get_action_for_day(ciclo: int, status: str, promessa: Optional[str], ref: date) -> Dict[str, str]:
    if status == STATUS_PAGO:
        return {"acao": "Título pago", "descricao": "Sem ação de cobrança", "responsavel_padrao": "", "prioridade": 99}

    promessa_dt = parse_iso_date(promessa)
    if promessa_dt and promessa_dt >= ref:
        return {
            "acao": "Aguardar promessa",
            "descricao": f"Cliente prometeu pagamento para {promessa_dt.strftime('%d/%m/%Y')}",
            "responsavel_padrao": "Financeiro",
            "prioridade": 3,
        }

    regua = load_regua()
    if regua.empty:
        return {"acao": "Cobrar", "descricao": "Sem régua cadastrada", "responsavel_padrao": "Financeiro", "prioridade": 5}

    applicable = regua[regua["dia"] <= int(ciclo)]
    if applicable.empty:
        row = regua.iloc[0]
    else:
        row = applicable.iloc[-1]

    return {
        "acao": str(row["acao"]),
        "descricao": str(row["descricao"]),
        "responsavel_padrao": str(row["responsavel_padrao"]),
        "prioridade": int(row["prioridade"]),
    }




def aplicar_base_bi_titulos_existentes() -> Dict[str, object]:
    """Preenche vendedor/gerente dos títulos já existentes usando a BASE BI.

    Regra de segurança:
    - não apaga histórico;
    - não recria tabelas;
    - só preenche vendedor/gerente quando o campo está vazio;
    - respeita o que foi informado manualmente no CRM.
    """
    backup_db("antes_aplicar_base_bi")
    try:
        faturamento_maps, faturamento_status = load_faturamento_maps_from_github()
    except Exception as exc:
        return {
            "ok": False,
            "mensagem": f"Erro ao ler BASE BI: {exc}",
            "analisados": 0,
            "localizados": 0,
            "titulos_atualizados": 0,
            "clientes_atualizados": 0,
            "sem_match": [],
        }

    conn = get_conn()
    try:
        titulos = pd.read_sql_query(
            """
            SELECT titulo_id, numero_titulo, cliente_codigo, loja, nome_cliente, vendedor, gerente, segmento,
                   razao_social, cnpj, contato, origem_vendedor, origem_gerente, origem_segmento, status
              FROM titulos
             WHERE status != ?
            """,
            conn,
            params=[STATUS_PAGO],
        )
        if titulos.empty:
            return {
                "ok": True,
                "mensagem": "Não há títulos em aberto para atualizar.",
                "analisados": 0,
                "localizados": 0,
                "titulos_atualizados": 0,
                "clientes_atualizados": 0,
                "sem_match": [],
            }

        now = datetime.now().isoformat(timespec="seconds")
        cur = conn.cursor()
        analisados = len(titulos)
        localizados = 0
        titulos_atualizados = 0
        clientes_atualizados_ids = set()
        sem_match = []

        for _, t in titulos.iterrows():
            row_lookup = pd.Series({
                "No. Titulo": t.get("numero_titulo", ""),
                "Cliente": t.get("cliente_codigo", ""),
                "Loja": t.get("loja", ""),
                "Nome Cliente": t.get("nome_cliente", ""),
            })
            info = get_faturamento_info_for(row_lookup, faturamento_maps)
            if not info or not (info.get("vendedor") or info.get("gerente") or info.get("razao_social")):
                if len(sem_match) < 80:
                    sem_match.append(f"{normalize_text(t.get('numero_titulo'))} • {normalize_text(t.get('nome_cliente'))}")
                continue

            localizados += 1
            vendedor_atual = normalize_text(t.get("vendedor"))
            gerente_atual = normalize_text(t.get("gerente"))
            razao_atual = normalize_text(t.get("razao_social"))
            cnpj_atual = normalize_text(t.get("cnpj"))
            contato_atual = normalize_text(t.get("contato"))
            segmento_atual = normalize_text(t.get("segmento"))

            replace_vendedor = should_replace_auto_field(vendedor_atual, t.get("origem_vendedor"))
            replace_gerente = should_replace_auto_field(gerente_atual, t.get("origem_gerente"))
            replace_segmento = should_replace_segment(segmento_atual, t.get("origem_segmento"))
            vendedor_novo = canonical_vendor_display(info.get("vendedor")) if replace_vendedor else canonical_vendor_display(vendedor_atual)
            gerente_novo = canonical_manager_display(info.get("gerente")) if replace_gerente else canonical_manager_display(gerente_atual)
            segmento_novo = canonical_segment_display(info.get("segmento")) if replace_segmento else canonical_segment_display(segmento_atual)
            origem_vendedor_nova = "BASE BI" if replace_vendedor and normalize_text(info.get("vendedor")) else normalize_text(t.get("origem_vendedor"))
            origem_gerente_nova = "BASE BI" if replace_gerente and normalize_text(info.get("gerente")) else normalize_text(t.get("origem_gerente"))
            origem_segmento_nova = "BASE BI" if replace_segmento and normalize_text(info.get("segmento")) else normalize_text(t.get("origem_segmento"))
            razao_nova = razao_atual or normalize_text(info.get("razao_social"))
            cnpj_novo = cnpj_atual or normalize_text(info.get("cnpj"))
            contato_novo = contato_atual or normalize_text(info.get("contato"))

            if (vendedor_novo != canonical_vendor_display(vendedor_atual) or gerente_novo != canonical_manager_display(gerente_atual) or
                segmento_novo != canonical_segment_display(segmento_atual) or razao_nova != razao_atual or
                cnpj_novo != cnpj_atual or contato_novo != contato_atual):
                cur.execute(
                    """
                    UPDATE titulos
                       SET vendedor = ?, gerente = ?, segmento = ?, razao_social = ?, cnpj = ?, contato = ?,
                           origem_vendedor = ?, origem_gerente = ?, origem_segmento = ?, updated_at = ?
                     WHERE titulo_id = ?
                    """,
                    (vendedor_novo, gerente_novo, segmento_novo, razao_nova, cnpj_novo, contato_novo,
                     origem_vendedor_nova, origem_gerente_nova, origem_segmento_nova,
                     now, t["titulo_id"]),
                )
                titulos_atualizados += 1

            cid = make_cliente_id(t.get("cliente_codigo", ""), t.get("loja", ""), t.get("nome_cliente", ""))
            # Atualiza o cadastro do cliente apenas preenchendo campos vazios.
            upsert_cliente_cadastro(
                conn,
                normalize_text(t.get("cliente_codigo")),
                normalize_text(t.get("loja")),
                normalize_text(t.get("nome_cliente")),
                razao_social=normalize_text(info.get("razao_social")),
                cnpj=normalize_text(info.get("cnpj")),
                contato=normalize_text(info.get("contato")),
            )
            clientes_atualizados_ids.add(cid)

        conn.commit()
        try:
            upload_db_to_github("aplicar_base_bi")
        except Exception:
            pass
        return {
            "ok": True,
            "mensagem": faturamento_status,
            "analisados": analisados,
            "localizados": localizados,
            "titulos_atualizados": titulos_atualizados,
            "clientes_atualizados": len(clientes_atualizados_ids),
            "sem_match": sem_match,
        }
    except Exception as exc:
        conn.rollback()
        return {
            "ok": False,
            "mensagem": f"Erro ao aplicar BASE BI: {exc}",
            "analisados": 0,
            "localizados": 0,
            "titulos_atualizados": 0,
            "clientes_atualizados": 0,
            "sem_match": [],
        }
    finally:
        conn.close()


def aplicar_relatorio_vendedor_titulos_existentes() -> Dict[str, object]:
    """Completa código/loja/razão social e cadastro usando o relatório por vendedor.

    A operação é retroativa, transacional e não altera histórico de cobrança.
    Vendedor e gerente só são usados quando os campos do título estão vazios.
    """
    backup_db("antes_aplicar_relatorio_vendedor")
    try:
        maps, status_base = load_relatorio_vendedor_maps()
    except Exception as exc:
        return {"ok": False, "mensagem": f"Erro ao ler relatório por vendedor: {exc}", "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}

    if not any(maps):
        return {"ok": False, "mensagem": status_base, "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}

    conn = get_conn()
    try:
        titulos = pd.read_sql_query(
            """
            SELECT titulo_id, prefixo, numero_titulo, parcela, tipo, cliente_codigo, loja, nome_cliente,
                   vendedor, gerente, razao_social, cnpj, contato, nome_fantasia,
                   telefone_financeiro, telefone_comercial, vencimento_titulo,
                   banco_status, saldo_corrigido, origem_vendedor, origem_gerente, status
              FROM titulos
             WHERE status != ?
            """,
            conn,
            params=[STATUS_PAGO],
        )
        if titulos.empty:
            return {"ok": True, "mensagem": "Não há títulos em aberto para atualizar.", "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}

        cad_map = get_cliente_cadastro_map(conn)
        now = datetime.now().isoformat(timespec="seconds")
        cur = conn.cursor()
        localizados = 0
        atualizados = 0
        clientes_ids = set()
        sem_match = []

        for _, t in titulos.iterrows():
            info = get_relatorio_vendedor_info_for(t, maps)
            if not info:
                if len(sem_match) < 80:
                    sem_match.append(f"{normalize_text(t.get('numero_titulo'))} • {normalize_text(t.get('nome_cliente'))}")
                continue
            localizados += 1

            old_code = normalize_text(t.get("cliente_codigo"))
            old_loja = normalize_text(t.get("loja"))
            nome_cliente = upper_text(t.get("nome_cliente"))
            new_code = info.get("cliente_codigo") or format_identifier(old_code, 6)
            new_loja = info.get("loja") or format_identifier(old_loja, 2)

            old_cid = make_cliente_id(old_code, old_loja, nome_cliente)
            new_cid = make_cliente_id(new_code, new_loja, nome_cliente)
            cad = cad_map.get(new_cid) or cad_map.get(old_cid) or {}

            vendedor_atual = canonical_vendor_display(t.get("vendedor"))
            gerente_atual = canonical_manager_display(t.get("gerente"))
            vendedor_novo = vendedor_atual or canonical_vendor_display(info.get("vendedor"))
            gerente_novo = gerente_atual or canonical_manager_display(info.get("gerente"))
            origem_vendedor = normalize_text(t.get("origem_vendedor")) or ("RELATÓRIO POR VENDEDOR" if not vendedor_atual and vendedor_novo else "")
            origem_gerente = normalize_text(t.get("origem_gerente")) or ("RELATÓRIO POR VENDEDOR" if not gerente_atual and gerente_novo else "")

            razao = normalize_text(t.get("razao_social")) or normalize_text(info.get("razao_social")) or normalize_text(cad.get("razao_social"))
            fantasia = normalize_text(t.get("nome_fantasia")) or normalize_text(info.get("nome_fantasia")) or normalize_text(cad.get("nome_fantasia")) or nome_cliente
            cnpj = normalize_text(t.get("cnpj")) or normalize_text(cad.get("cnpj"))
            contato = normalize_text(t.get("contato")) or normalize_text(cad.get("contato"))
            tel_fin = normalize_text(t.get("telefone_financeiro")) or normalize_text(info.get("telefone_financeiro")) or normalize_text(cad.get("telefone_financeiro"))
            tel_com = normalize_text(t.get("telefone_comercial")) or normalize_text(info.get("telefone_comercial")) or normalize_text(cad.get("telefone_comercial"))
            venc_titulo = normalize_text(t.get("vencimento_titulo")) or normalize_text(info.get("vencimento_titulo"))
            banco_status = normalize_text(t.get("banco_status")) or normalize_text(info.get("banco_status"))
            saldo_corrigido_atual = float(t.get("saldo_corrigido") or 0)
            saldo_corrigido = saldo_corrigido_atual or float(info.get("saldo_corrigido") or 0)

            changed = any([
                new_code != old_code, new_loja != old_loja,
                vendedor_novo != vendedor_atual, gerente_novo != gerente_atual,
                razao != normalize_text(t.get("razao_social")),
                fantasia != normalize_text(t.get("nome_fantasia")),
                tel_fin != normalize_text(t.get("telefone_financeiro")),
                tel_com != normalize_text(t.get("telefone_comercial")),
                venc_titulo != normalize_text(t.get("vencimento_titulo")),
                banco_status != normalize_text(t.get("banco_status")),
                saldo_corrigido != saldo_corrigido_atual,
            ])
            if changed:
                cur.execute(
                    """
                    UPDATE titulos
                       SET cliente_codigo = ?, loja = ?, vendedor = ?, gerente = ?, razao_social = ?, cnpj = ?, contato = ?,
                           nome_fantasia = ?, telefone_financeiro = ?, telefone_comercial = ?, vencimento_titulo = ?,
                           banco_status = ?, saldo_corrigido = ?, origem_vendedor = ?, origem_gerente = ?, updated_at = ?
                     WHERE titulo_id = ?
                    """,
                    (new_code, new_loja, vendedor_novo, gerente_novo, razao, cnpj, contato, fantasia,
                     tel_fin, tel_com, venc_titulo, banco_status, saldo_corrigido,
                     origem_vendedor, origem_gerente, now, t["titulo_id"]),
                )
                atualizados += 1

            upsert_cliente_cadastro(
                conn,
                new_code,
                new_loja,
                nome_cliente,
                vendedor=normalize_text(cad.get("vendedor")),
                gerente=normalize_text(cad.get("gerente")),
                observacao=normalize_text(cad.get("observacao")),
                tipo_cliente=normalize_text(cad.get("tipo_cliente")),
                cobrador=normalize_text(cad.get("cobrador")),
                razao_social=razao,
                cnpj=cnpj,
                contato=contato,
                nome_fantasia=fantasia,
                telefone_financeiro=tel_fin,
                telefone_comercial=tel_com,
                endereco=info.get("endereco", ""),
                bairro=info.get("bairro", ""),
                municipio=info.get("municipio", ""),
                uf=info.get("uf", ""),
                cep=info.get("cep", ""),
                email_nfe=info.get("email_nfe", ""),
                email_comercial=info.get("email_comercial", ""),
                email_financeiro=info.get("email_financeiro", ""),
            )
            clientes_ids.add(new_cid)

        conn.commit()
        return {
            "ok": True,
            "mensagem": status_base,
            "analisados": len(titulos),
            "localizados": localizados,
            "titulos_atualizados": atualizados,
            "clientes_atualizados": len(clientes_ids),
            "sem_match": sem_match,
        }
    except Exception as exc:
        conn.rollback()
        return {"ok": False, "mensagem": f"Erro ao aplicar relatório por vendedor: {exc}", "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}
    finally:
        conn.close()


def aplicar_cadastro_clientes_titulos_existentes() -> Dict[str, object]:
    """Completa dados cadastrais a partir do MATR021/cadastro de clientes.

    Preenche código, loja, razão social, nome fantasia, CNPJ, contato e telefones
    somente quando estiverem vazios ou quando o código/loja precisarem de zeros.
    Não altera histórico de cobrança, ações ou agenda.
    """
    backup_db("antes_aplicar_cadastro_clientes")
    try:
        maps, status_base = load_cadastro_clientes_maps()
    except Exception as exc:
        return {"ok": False, "mensagem": f"Erro ao ler cadastro de clientes: {exc}", "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}

    if not any(maps):
        return {"ok": False, "mensagem": status_base, "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}

    conn = get_conn()
    try:
        titulos = pd.read_sql_query(
            """
            SELECT titulo_id, prefixo, numero_titulo, parcela, tipo, cliente_codigo, loja, nome_cliente,
                   razao_social, cnpj, contato, nome_fantasia, telefone_financeiro,
                   telefone_comercial, status
              FROM titulos
             WHERE status != ?
            """,
            conn,
            params=[STATUS_PAGO],
        )
        if titulos.empty:
            return {"ok": True, "mensagem": "Não há títulos em aberto para atualizar.", "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}

        cad_map = get_cliente_cadastro_map(conn)
        now = datetime.now().isoformat(timespec="seconds")
        cur = conn.cursor()
        localizados = 0
        atualizados = 0
        clientes_ids = set()
        sem_match = []

        for _, t in titulos.iterrows():
            info = get_cadastro_cliente_info_for(t, maps)
            if not info:
                if len(sem_match) < 80:
                    sem_match.append(f"{normalize_text(t.get('cliente_codigo'))}-{normalize_text(t.get('loja'))} • {normalize_text(t.get('nome_cliente'))}")
                continue
            localizados += 1

            old_code = normalize_text(t.get("cliente_codigo"))
            old_loja = normalize_text(t.get("loja"))
            nome_cliente = upper_text(t.get("nome_cliente")) or upper_text(info.get("razao_social"))
            new_code = info.get("cliente_codigo") or format_identifier(old_code, 6)
            new_loja = info.get("loja") or format_identifier(old_loja, 2)
            old_cid = make_cliente_id(old_code, old_loja, nome_cliente)
            new_cid = make_cliente_id(new_code, new_loja, nome_cliente)
            cad = cad_map.get(new_cid) or cad_map.get(old_cid) or {}

            razao = normalize_text(t.get("razao_social")) or normalize_text(cad.get("razao_social")) or normalize_text(info.get("razao_social")) or nome_cliente
            fantasia = normalize_text(t.get("nome_fantasia")) or normalize_text(cad.get("nome_fantasia")) or normalize_text(info.get("nome_fantasia")) or nome_cliente
            cnpj = normalize_text(t.get("cnpj")) or normalize_text(cad.get("cnpj")) or normalize_text(info.get("cnpj"))
            contato = normalize_text(t.get("contato")) or normalize_text(cad.get("contato")) or normalize_text(info.get("contato"))
            tel_fin = normalize_text(t.get("telefone_financeiro")) or normalize_text(cad.get("telefone_financeiro")) or normalize_text(info.get("telefone_financeiro"))
            tel_com = normalize_text(t.get("telefone_comercial")) or normalize_text(cad.get("telefone_comercial")) or normalize_text(info.get("telefone_comercial"))

            changed = any([
                new_code != old_code,
                new_loja != old_loja,
                razao != normalize_text(t.get("razao_social")),
                fantasia != normalize_text(t.get("nome_fantasia")),
                cnpj != normalize_text(t.get("cnpj")),
                contato != normalize_text(t.get("contato")),
                tel_fin != normalize_text(t.get("telefone_financeiro")),
                tel_com != normalize_text(t.get("telefone_comercial")),
            ])
            if changed:
                cur.execute(
                    """
                    UPDATE titulos
                       SET cliente_codigo = ?, loja = ?, razao_social = ?, cnpj = ?, contato = ?,
                           nome_fantasia = ?, telefone_financeiro = ?, telefone_comercial = ?, updated_at = ?
                     WHERE titulo_id = ?
                    """,
                    (new_code, new_loja, upper_text(razao), upper_text(cnpj), upper_text(contato),
                     upper_text(fantasia), upper_text(tel_fin), upper_text(tel_com), now, t["titulo_id"]),
                )
                atualizados += 1

            upsert_cliente_cadastro(
                conn,
                new_code,
                new_loja,
                nome_cliente,
                vendedor=normalize_text(cad.get("vendedor")),
                gerente=normalize_text(cad.get("gerente")),
                observacao=normalize_text(cad.get("observacao")),
                tipo_cliente=normalize_text(cad.get("tipo_cliente")),
                cobrador=normalize_text(cad.get("cobrador")),
                razao_social=razao,
                cnpj=cnpj,
                contato=contato,
                nome_fantasia=fantasia,
                telefone_financeiro=tel_fin,
                telefone_comercial=tel_com,
            )
            clientes_ids.add(new_cid)

        conn.commit()
        try:
            upload_db_to_github("aplicar_cadastro_clientes")
        except Exception:
            pass
        return {
            "ok": True,
            "mensagem": status_base,
            "analisados": len(titulos),
            "localizados": localizados,
            "titulos_atualizados": atualizados,
            "clientes_atualizados": len(clientes_ids),
            "sem_match": sem_match,
        }
    except Exception as exc:
        conn.rollback()
        return {"ok": False, "mensagem": f"Erro ao aplicar cadastro de clientes: {exc}", "analisados": 0, "localizados": 0, "titulos_atualizados": 0, "clientes_atualizados": 0, "sem_match": []}
    finally:
        conn.close()


def process_upload(df: pd.DataFrame, data_ref: date, arquivo_nome: str) -> Tuple[int, int, int, float, int, int, str]:
    backup_db("antes_upload")
    conn = get_conn()
    try:
        cur = conn.cursor()
        now = datetime.now().isoformat(timespec="seconds")
        data_ref_str = data_ref.isoformat()
        current_ids = set(df["titulo_id"].astype(str).tolist())
        cadastro_map = get_cliente_cadastro_map(conn)
        cad_by_name = {}
        for cid_key, cad_info in cadastro_map.items():
            name_key = normalize_col_key(cad_info.get("nome_cliente", ""))
            if name_key and name_key not in cad_by_name:
                cad_by_name[name_key] = cad_info

        try:
            faturamento_maps, faturamento_status = load_faturamento_maps_from_github()
        except Exception as exc:
            faturamento_maps, faturamento_status = ({}, {}, {}, {}), f"Erro ao ler BASE BI: {exc}"
        try:
            rel_vendedor_maps, rel_vendedor_status = load_relatorio_vendedor_maps()
        except Exception as exc:
            rel_vendedor_maps, rel_vendedor_status = ({}, {}, {}), f"Erro ao ler relatório por vendedor: {exc}"
        try:
            cadastro_clientes_maps, cadastro_clientes_status = load_cadastro_clientes_maps()
        except Exception as exc:
            cadastro_clientes_maps, cadastro_clientes_status = ({}, {}), f"Erro ao ler cadastro de clientes: {exc}"

        existing = pd.read_sql_query("SELECT titulo_id, status, primeira_aparicao, ultima_aparicao FROM titulos", conn)
        existing_ids = set(existing["titulo_id"].astype(str).tolist()) if not existing.empty else set()
        active_existing_ids = set(existing.loc[existing["status"] != STATUS_PAGO, "titulo_id"].astype(str).tolist()) if not existing.empty else set()

        novos = 0
        atualizados = 0
        base_bi_cruzados = 0
        base_bi_nao_localizados = 0
        cadastro_clientes_cruzados = 0
        rel_vendedor_cruzados = 0

        for _, row in df.iterrows():
            tid = str(row["titulo_id"])
            raw_code = normalize_text(row.get("Cliente"))
            raw_loja = normalize_text(row.get("Loja"))
            nome_cliente = upper_text(row.get("Nome Cliente"))

            auto_info = get_faturamento_info_for(row, faturamento_maps)
            cad_info = get_relatorio_vendedor_info_for(row, rel_vendedor_maps)
            cad_cliente_info = get_cadastro_cliente_info_for(row, cadastro_clientes_maps)

            if cad_cliente_info:
                cadastro_clientes_cruzados += 1
            if cad_info:
                rel_vendedor_cruzados += 1

            cliente_codigo = cad_info.get("cliente_codigo") or cad_cliente_info.get("cliente_codigo") or format_identifier(raw_code, 6)
            loja = cad_info.get("loja") or cad_cliente_info.get("loja") or format_identifier(raw_loja, 2)
            cid_final = make_cliente_id(cliente_codigo, loja, nome_cliente)
            cid_raw = make_cliente_id(raw_code, raw_loja, nome_cliente)
            cad = (
                cadastro_map.get(cid_final)
                or cadastro_map.get(cid_raw)
                or cad_by_name.get(normalize_col_key(nome_cliente))
                or {}
            )

            if auto_info and (auto_info.get("vendedor") or auto_info.get("gerente")):
                base_bi_cruzados += 1
            else:
                base_bi_nao_localizados += 1

            # Comercial: NF/segmento da BASE BI; relatório por vendedor como fallback;
            # cadastro manual do cliente somente quando as duas bases não trouxerem responsável.
            vendedor_cad = canonical_vendor_display(
                auto_info.get("vendedor", "") or cad_info.get("vendedor", "") or cad.get("vendedor", "") or ""
            )
            gerente_cad = canonical_manager_display(
                auto_info.get("gerente", "") or cad_info.get("gerente", "") or cad.get("gerente", "") or ""
            )
            segmento_cad = canonical_segment_display(auto_info.get("segmento", "") or "")
            obs_cad = str(cad.get("observacao", "") or "")

            razao_cad = upper_text(
                cad.get("razao_social", "")
                or cad_cliente_info.get("razao_social", "")
                or cad_info.get("razao_social", "")
                or auto_info.get("razao_social", "")
                or nome_cliente
            )
            nome_fantasia_cad = upper_text(
                cad.get("nome_fantasia", "")
                or cad_cliente_info.get("nome_fantasia", "")
                or cad_info.get("nome_fantasia", "")
                or nome_cliente
            )
            cnpj_cad = upper_text(cad.get("cnpj", "") or cad_cliente_info.get("cnpj", "") or auto_info.get("cnpj", "") or "")
            contato_cad = upper_text(cad.get("contato", "") or cad_cliente_info.get("contato", "") or auto_info.get("contato", "") or "")
            tel_fin_cad = upper_text(cad.get("telefone_financeiro", "") or cad_cliente_info.get("telefone_financeiro", "") or cad_info.get("telefone_financeiro", "") or "")
            tel_com_cad = upper_text(cad.get("telefone_comercial", "") or cad_cliente_info.get("telefone_comercial", "") or cad_info.get("telefone_comercial", "") or "")
            venc_titulo_cad = normalize_text(cad_info.get("vencimento_titulo", "") or row.get("vencimento_str") or "")
            banco_status_cad = upper_text(cad_info.get("banco_status", "") or "")
            saldo_corrigido_cad = float(cad_info.get("saldo_corrigido", 0) or 0)
            if saldo_corrigido_cad <= 0:
                saldo_corrigido_cad = float(row.get("Saldo a receber", 0) or 0) + float(row.get("Multa", 0) or 0) + float(row.get("Juros", 0) or 0)

            upsert_cliente_cadastro(
                conn,
                cliente_codigo,
                loja,
                nome_cliente,
                razao_social=razao_cad,
                cnpj=cnpj_cad,
                contato=contato_cad,
                nome_fantasia=nome_fantasia_cad,
                telefone_financeiro=tel_fin_cad,
                telefone_comercial=tel_com_cad,
                endereco=cad_cliente_info.get("endereco", "") or cad.get("endereco", ""),
                bairro=cad_cliente_info.get("bairro", "") or cad.get("bairro", ""),
                municipio=cad_cliente_info.get("municipio", "") or cad.get("municipio", ""),
                uf=cad_cliente_info.get("uf", "") or cad.get("uf", ""),
                cep=cad_cliente_info.get("cep", "") or cad.get("cep", ""),
                email_nfe=cad_cliente_info.get("email_nfe", "") or cad.get("email_nfe", ""),
                email_comercial=cad_cliente_info.get("email_comercial", "") or cad.get("email_comercial", ""),
                email_financeiro=cad_cliente_info.get("email_financeiro", "") or cad.get("email_financeiro", ""),
                observacao=obs_cad,
                tipo_cliente=normalize_text(cad.get("tipo_cliente", "")),
                cobrador=normalize_text(cad.get("cobrador", "")),
                vendedor=normalize_text(cad.get("vendedor", "")),
                gerente=normalize_text(cad.get("gerente", "")),
            )

            if tid in existing_ids:
                old_row = cur.execute(
                    """
                    SELECT primeira_aparicao, vendedor, gerente, segmento, observacao_atual,
                           razao_social, cnpj, contato, nome_fantasia, telefone_financeiro,
                           telefone_comercial, vencimento_titulo, banco_status, saldo_corrigido,
                           origem_vendedor, origem_gerente, origem_segmento
                      FROM titulos WHERE titulo_id = ?
                    """,
                    (tid,),
                ).fetchone()
                first = old_row["primeira_aparicao"]
                ciclo = calcular_ciclo(first, data_ref)
                old_vendedor = str(old_row["vendedor"] or "")
                old_gerente = str(old_row["gerente"] or "")
                old_segmento = str(old_row["segmento"] or "")
                replace_vendedor = should_replace_auto_field(old_vendedor, str(old_row["origem_vendedor"] or ""))
                replace_gerente = should_replace_auto_field(old_gerente, str(old_row["origem_gerente"] or ""))
                replace_segmento = should_replace_segment(old_segmento, str(old_row["origem_segmento"] or ""))

                vendedor_final = vendedor_cad if replace_vendedor else canonical_vendor_display(old_vendedor)
                gerente_final = gerente_cad if replace_gerente else canonical_manager_display(old_gerente)
                segmento_final = segmento_cad if replace_segmento else canonical_segment_display(old_segmento)

                source_vendor = "BASE BI" if normalize_text(auto_info.get("vendedor")) else ("RELATÓRIO POR VENDEDOR" if normalize_text(cad_info.get("vendedor")) else "")
                source_manager = "BASE BI" if normalize_text(auto_info.get("gerente")) else ("RELATÓRIO POR VENDEDOR" if normalize_text(cad_info.get("gerente")) else "")
                origem_vendedor_final = source_vendor if replace_vendedor and vendedor_final else str(old_row["origem_vendedor"] or "")
                origem_gerente_final = source_manager if replace_gerente and gerente_final else str(old_row["origem_gerente"] or "")
                origem_segmento_final = "BASE BI" if replace_segmento and normalize_text(auto_info.get("segmento")) else str(old_row["origem_segmento"] or "")

                obs_final = obs_cad or str(old_row["observacao_atual"] or "")
                razao_final = str(old_row["razao_social"] or "") or razao_cad
                cnpj_final = str(old_row["cnpj"] or "") or cnpj_cad
                contato_final = str(old_row["contato"] or "") or contato_cad
                fantasia_final = str(old_row["nome_fantasia"] or "") or nome_fantasia_cad
                tel_fin_final = str(old_row["telefone_financeiro"] or "") or tel_fin_cad
                tel_com_final = str(old_row["telefone_comercial"] or "") or tel_com_cad
                venc_titulo_final = str(old_row["vencimento_titulo"] or "") or venc_titulo_cad
                banco_status_final = str(old_row["banco_status"] or "") or banco_status_cad
                saldo_corrigido_final = float(old_row["saldo_corrigido"] or 0) or saldo_corrigido_cad

                cur.execute(
                    """
                    UPDATE titulos
                       SET filial = ?, prefixo = ?, numero_titulo = ?, parcela = ?, tipo = ?,
                           cliente_codigo = ?, loja = ?, nome_cliente = ?, dt_emissao = ?, vencimento = ?,
                           vencimento_titulo = ?, valor_titulo = ?, saldo_atual = ?, multa = ?, juros = ?,
                           saldo_corrigido = ?, banco_status = ?, vendedor = ?, gerente = ?, segmento = ?,
                           observacao_atual = ?, razao_social = ?, cnpj = ?, contato = ?, nome_fantasia = ?,
                           telefone_financeiro = ?, telefone_comercial = ?,
                           origem_vendedor = ?, origem_gerente = ?, origem_segmento = ?,
                           status = CASE WHEN status = 'Pago' THEN 'Em cobrança' ELSE status END,
                           ultima_aparicao = ?, data_baixa = NULL, ciclo_cobranca = ?, updated_at = ?
                     WHERE titulo_id = ?
                    """,
                    (
                        normalize_text(row.get("Filial")), normalize_text(row.get("Prefixo")), normalize_text(row.get("No. Titulo")),
                        normalize_text(row.get("Parcela")), normalize_text(row.get("Tipo")), cliente_codigo, loja,
                        nome_cliente, row.get("dt_emissao_str"), row.get("vencimento_str"), venc_titulo_final,
                        float(row.get("Vlr.Titulo", 0)), float(row.get("Saldo a receber", 0)),
                        float(row.get("Multa", 0)), float(row.get("Juros", 0)), saldo_corrigido_final,
                        banco_status_final, vendedor_final, gerente_final, segmento_final, obs_final,
                        razao_final, cnpj_final, contato_final, fantasia_final, tel_fin_final, tel_com_final,
                        origem_vendedor_final, origem_gerente_final, origem_segmento_final,
                        data_ref_str, ciclo, now, tid,
                    ),
                )
                atualizados += 1
            else:
                source_vendor = "BASE BI" if normalize_text(auto_info.get("vendedor")) else ("RELATÓRIO POR VENDEDOR" if normalize_text(cad_info.get("vendedor")) else "")
                source_manager = "BASE BI" if normalize_text(auto_info.get("gerente")) else ("RELATÓRIO POR VENDEDOR" if normalize_text(cad_info.get("gerente")) else "")
                cur.execute(
                    """
                    INSERT INTO titulos (
                        titulo_id, filial, prefixo, numero_titulo, parcela, tipo, cliente_codigo, loja,
                        nome_cliente, dt_emissao, vencimento, vencimento_titulo, valor_titulo, saldo_original,
                        saldo_atual, multa, juros, saldo_corrigido, banco_status, vendedor, gerente, segmento,
                        observacao_atual, razao_social, cnpj, contato, nome_fantasia, telefone_financeiro,
                        telefone_comercial, origem_vendedor, origem_gerente, origem_segmento, status,
                        primeira_aparicao, ultima_aparicao, ciclo_cobranca, created_at, updated_at
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        tid, normalize_text(row.get("Filial")), normalize_text(row.get("Prefixo")), normalize_text(row.get("No. Titulo")),
                        normalize_text(row.get("Parcela")), normalize_text(row.get("Tipo")), cliente_codigo, loja,
                        nome_cliente, row.get("dt_emissao_str"), row.get("vencimento_str"), venc_titulo_cad,
                        float(row.get("Vlr.Titulo", 0)), float(row.get("Saldo a receber", 0)),
                        float(row.get("Saldo a receber", 0)), float(row.get("Multa", 0)), float(row.get("Juros", 0)),
                        saldo_corrigido_cad, banco_status_cad, vendedor_cad, gerente_cad, segmento_cad, obs_cad,
                        razao_cad, cnpj_cad, contato_cad, nome_fantasia_cad, tel_fin_cad, tel_com_cad,
                        source_vendor, source_manager, "BASE BI" if normalize_text(auto_info.get("segmento")) else "",
                        STATUS_ATIVO, data_ref_str, data_ref_str, 1, now, now,
                    ),
                )
                cur.execute(
                    "INSERT INTO historico_acoes (titulo_id, data_acao, tipo_acao, responsavel, observacao, created_at) VALUES (?, ?, ?, ?, ?, ?)",
                    (tid, data_ref_str, "Entrada na régua", "Sistema", "Título incluído no CRM financeiro.", now),
                )
                novos += 1

        paid_ids = sorted(active_existing_ids - current_ids)
        for tid in paid_ids:
            cur.execute(
                "UPDATE titulos SET status = ?, data_baixa = ?, updated_at = ? WHERE titulo_id = ?",
                (STATUS_PAGO, data_ref_str, now, tid),
            )
            cur.execute(
                "INSERT INTO historico_acoes (titulo_id, data_acao, tipo_acao, responsavel, observacao, created_at) VALUES (?, ?, ?, ?, ?, ?)",
                (tid, data_ref_str, "Baixa automática", "Sistema", "Título saiu do relatório diário.", now),
            )

        valor_aberto = float(df["Saldo a receber"].sum())
        status_fontes = f"{faturamento_status} | {rel_vendedor_status} | {cadastro_clientes_status} | Enriquecimento automático: novos títulos buscam BASE BI, relatório por vendedor e cadastro de clientes no upload. Cadastro cruzado: {cadastro_clientes_cruzados}; relatório vendedor cruzado: {rel_vendedor_cruzados}"
        cur.execute(
            """
            INSERT INTO uploads (data_referencia, arquivo, qtd_linhas, novos, atualizados, pagos, valor_aberto, base_bi_cruzados, base_bi_nao_localizados, base_bi_status, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (data_ref_str, arquivo_nome, len(df), novos, atualizados, len(paid_ids), valor_aberto, base_bi_cruzados, base_bi_nao_localizados, status_fontes, now),
        )
        conn.commit()
        return novos, atualizados, len(paid_ids), valor_aberto, base_bi_cruzados, base_bi_nao_localizados, status_fontes
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()

def load_titulos(status_filter: Optional[str] = None) -> pd.DataFrame:
    conn = get_conn()
    query = "SELECT * FROM titulos"
    params = []
    if status_filter:
        query += " WHERE status = ?"
        params.append(status_filter)
    df = pd.read_sql_query(query, conn, params=params)
    conn.close()
    return df


def load_historico(titulo_id: Optional[str] = None) -> pd.DataFrame:
    conn = get_conn()
    if titulo_id:
        df = pd.read_sql_query("SELECT * FROM historico_acoes WHERE titulo_id = ? ORDER BY data_acao DESC, id DESC", conn, params=[titulo_id])
    else:
        df = pd.read_sql_query("SELECT * FROM historico_acoes ORDER BY data_acao DESC, id DESC LIMIT 500", conn)
    conn.close()
    return df


def contar_historico_cliente(cliente_codigo: str, loja: str, nome_cliente: str) -> int:
    """Conta registros de histórico vinculados aos títulos do cliente, para validação pós-salvamento."""
    conn = get_conn()
    try:
        where, params = _cliente_where_clause(cliente_codigo, loja, nome_cliente)
        row = conn.execute(
            f"""
            SELECT COUNT(*) AS total
              FROM historico_acoes h
              JOIN titulos t ON t.titulo_id = h.titulo_id
             WHERE {where}
            """,
            params,
        ).fetchone()
        return int(row["total"] if row else 0)
    finally:
        conn.close()



def update_cliente_meta(cliente_codigo: str, loja: str, nome_cliente: str, tipo_cliente: str, cobrador: str) -> None:
    """Salva tipo de cliente e responsável da cobrança no cadastro do cliente."""
    backup_db("antes_cliente_meta")
    conn = get_conn()
    now = datetime.now().isoformat(timespec="seconds")
    cid = make_cliente_id(cliente_codigo, loja, nome_cliente)
    upsert_cliente_cadastro(conn, cliente_codigo, loja, nome_cliente, tipo_cliente=tipo_cliente, cobrador=cobrador)
    conn.execute(
        "UPDATE clientes SET tipo_cliente = ?, cobrador = ?, updated_at = ? WHERE cliente_id = ?",
        (tipo_cliente or "Não especial", upper_text(cobrador), now, cid),
    )
    conn.commit()
    conn.close()


def add_agenda_retorno(cliente_codigo: str, loja: str, nome_cliente: str, data_retorno: date, motivo: str, responsavel: str) -> str:
    """Inclui ou atualiza o único lembrete pendente do cliente.

    Evita duplicidade quando o usuário clica em salvar mais de uma vez ou troca a data do retorno.
    Regra prática: um cliente deve ter apenas uma agenda pendente ativa; se já existir, atualiza a data.
    """
    backup_db("antes_agenda")
    conn = get_conn()
    now = datetime.now().isoformat(timespec="seconds")
    cid = make_cliente_id(cliente_codigo, loja, nome_cliente)
    data_iso = data_retorno.isoformat()
    motivo_limpo = upper_text(motivo or "Retorno programado")
    responsavel_limpo = upper_text(responsavel or "Financeiro")

    existente = conn.execute(
        """
        SELECT id
        FROM agenda_retorno
        WHERE cliente_id = ?
          AND status = 'Pendente'
        ORDER BY id DESC
        LIMIT 1
        """,
        (cid,),
    ).fetchone()

    if existente:
        conn.execute(
            """
            UPDATE agenda_retorno
               SET data_retorno = ?, motivo = ?, responsavel = ?, nome_cliente = ?, cliente_codigo = ?, loja = ?, updated_at = ?
             WHERE id = ?
            """,
            (data_iso, motivo_limpo, responsavel_limpo, nome_cliente, cliente_codigo, loja, now, int(existente[0])),
        )
        resultado = "atualizado"
    else:
        conn.execute(
            """
            INSERT INTO agenda_retorno (cliente_id, cliente_codigo, loja, nome_cliente, data_retorno, motivo, responsavel, status, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, 'Pendente', ?, ?)
            """,
            (cid, cliente_codigo, loja, nome_cliente, data_iso, motivo_limpo, responsavel_limpo, now, now),
        )
        resultado = "incluído"

    conn.commit()
    conn.close()
    return resultado


def load_agenda(status: str = "Pendente") -> pd.DataFrame:
    conn = get_conn()
    query = "SELECT * FROM agenda_retorno"
    params = []
    if status != "Todos":
        query += " WHERE status = ?"
        params.append(status)
    query += " ORDER BY data_retorno ASC, nome_cliente ASC"
    df = pd.read_sql_query(query, conn, params=params)
    conn.close()
    return df


