def upsert_cliente_cadastro(
    conn: sqlite3.Connection,
    cliente_codigo: str,
    loja: str,
    nome_cliente: str,
    vendedor: str = "",
    gerente: str = "",
    observacao: str = "",
    tipo_cliente: str = "",
    cobrador: str = "",
    razao_social: str = "",
    cnpj: str = "",
    contato: str = "",
    nome_fantasia: str = "",
    telefone_financeiro: str = "",
    telefone_comercial: str = "",
    endereco: str = "",
    bairro: str = "",
    municipio: str = "",
    uf: str = "",
    cep: str = "",
    email_nfe: str = "",
    email_comercial: str = "",
    email_financeiro: str = "",
) -> None:
    now = datetime.now().isoformat(timespec="seconds")
    cliente_codigo = format_identifier(cliente_codigo, 6)
    loja = format_identifier(loja, 2)
    cid = make_cliente_id(cliente_codigo, loja, nome_cliente)
    conn.execute(
        """
        INSERT INTO clientes (
            cliente_id, cliente_codigo, loja, nome_cliente, vendedor, gerente,
            tipo_cliente, cobrador, observacao, razao_social, cnpj, contato,
            nome_fantasia, telefone_financeiro, telefone_comercial, endereco, bairro, municipio, uf, cep,
            email_nfe, email_comercial, email_financeiro, created_at, updated_at
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(cliente_id) DO UPDATE SET
            cliente_codigo = excluded.cliente_codigo,
            loja = excluded.loja,
            nome_cliente = excluded.nome_cliente,
            vendedor = CASE WHEN excluded.vendedor != '' THEN excluded.vendedor ELSE clientes.vendedor END,
            gerente = CASE WHEN excluded.gerente != '' THEN excluded.gerente ELSE clientes.gerente END,
            tipo_cliente = CASE WHEN excluded.tipo_cliente != '' THEN excluded.tipo_cliente ELSE COALESCE(NULLIF(clientes.tipo_cliente, ''), 'Não especial') END,
            cobrador = CASE WHEN excluded.cobrador != '' THEN excluded.cobrador ELSE COALESCE(clientes.cobrador, '') END,
            observacao = CASE WHEN excluded.observacao != '' THEN excluded.observacao ELSE clientes.observacao END,
            razao_social = CASE WHEN excluded.razao_social != '' THEN excluded.razao_social ELSE COALESCE(clientes.razao_social, '') END,
            cnpj = CASE WHEN excluded.cnpj != '' THEN excluded.cnpj ELSE COALESCE(clientes.cnpj, '') END,
            contato = CASE WHEN excluded.contato != '' THEN excluded.contato ELSE COALESCE(clientes.contato, '') END,
            nome_fantasia = CASE WHEN excluded.nome_fantasia != '' THEN excluded.nome_fantasia ELSE COALESCE(clientes.nome_fantasia, '') END,
            telefone_financeiro = CASE WHEN excluded.telefone_financeiro != '' THEN excluded.telefone_financeiro ELSE COALESCE(clientes.telefone_financeiro, '') END,
            telefone_comercial = CASE WHEN excluded.telefone_comercial != '' THEN excluded.telefone_comercial ELSE COALESCE(clientes.telefone_comercial, '') END,
            endereco = CASE WHEN excluded.endereco != '' THEN excluded.endereco ELSE COALESCE(clientes.endereco, '') END,
            bairro = CASE WHEN excluded.bairro != '' THEN excluded.bairro ELSE COALESCE(clientes.bairro, '') END,
            municipio = CASE WHEN excluded.municipio != '' THEN excluded.municipio ELSE COALESCE(clientes.municipio, '') END,
            uf = CASE WHEN excluded.uf != '' THEN excluded.uf ELSE COALESCE(clientes.uf, '') END,
            cep = CASE WHEN excluded.cep != '' THEN excluded.cep ELSE COALESCE(clientes.cep, '') END,
            email_nfe = CASE WHEN excluded.email_nfe != '' THEN excluded.email_nfe ELSE COALESCE(clientes.email_nfe, '') END,
            email_comercial = CASE WHEN excluded.email_comercial != '' THEN excluded.email_comercial ELSE COALESCE(clientes.email_comercial, '') END,
            email_financeiro = CASE WHEN excluded.email_financeiro != '' THEN excluded.email_financeiro ELSE COALESCE(clientes.email_financeiro, '') END,
            updated_at = excluded.updated_at
        """,
        (
            cid, cliente_codigo, loja, upper_text(nome_cliente), upper_text(vendedor), upper_text(gerente),
            (tipo_cliente or "").strip(), upper_text(cobrador), upper_text(observacao), upper_text(razao_social),
            upper_text(cnpj), upper_text(contato), upper_text(nome_fantasia),
            upper_text(telefone_financeiro), upper_text(telefone_comercial), upper_text(endereco), upper_text(bairro),
            upper_text(municipio), upper_text(uf), upper_text(cep), upper_text(email_nfe), upper_text(email_comercial),
            upper_text(email_financeiro), now, now,
        ),
    )

def _table_columns(conn: sqlite3.Connection, table: str) -> List[str]:
    try:
        return [str(r[1]) for r in conn.execute(f"PRAGMA table_info({table})").fetchall()]
    except Exception:
        return []


def get_cliente_cadastro_map(conn: sqlite3.Connection) -> Dict[str, Dict[str, str]]:
    """Retorna cadastro usando chave canônica, com leitura segura para bancos antigos."""
    base_cols = [
        "cliente_id", "cliente_codigo", "loja", "nome_cliente", "vendedor", "gerente", "observacao",
        "tipo_cliente", "cobrador", "razao_social", "cnpj", "contato", "nome_fantasia",
        "telefone_financeiro", "telefone_comercial", "endereco", "bairro", "municipio", "uf", "cep",
        "email_nfe", "email_comercial", "email_financeiro",
        "notif_data_contrato", "notif_contraprestacao", "notif_prazo", "notif_teams_link", "notif_assinatura",
    ]

    existing_cols = set(_table_columns(conn, "clientes"))
    if not existing_cols:
        return {}

    selected_cols = [c for c in base_cols if c in existing_cols]
    if not selected_cols:
        return {}

    try:
        df = pd.read_sql_query(
            f"SELECT {', '.join(selected_cols)} FROM clientes",
            conn,
        )
    except Exception:
        # Banco legado com alguma coluna pendente de migração: evita derrubar a tela Cliente.
        fallback_cols = [c for c in ["cliente_id", "cliente_codigo", "loja", "nome_cliente", "vendedor", "gerente", "observacao"] if c in existing_cols]
        if not fallback_cols:
            return {}
        df = pd.read_sql_query(f"SELECT {', '.join(fallback_cols)} FROM clientes", conn)

    for c in base_cols:
        if c not in df.columns:
            df[c] = ""

    if df.empty:
        return {}

    result: Dict[str, Dict[str, str]] = {}
    score_cols = [
        "vendedor", "gerente", "observacao", "tipo_cliente", "cobrador",
        "razao_social", "cnpj", "contato", "nome_fantasia",
        "telefone_financeiro", "telefone_comercial", "endereco", "bairro", "municipio", "uf", "cep",
        "email_nfe", "email_comercial", "email_financeiro",
        "notif_data_contrato", "notif_contraprestacao", "notif_prazo", "notif_teams_link", "notif_assinatura",
    ]
    for _, row in df.iterrows():
        key = make_cliente_id(row.get("cliente_codigo", ""), row.get("loja", ""), row.get("nome_cliente", ""))
        data = row.to_dict()
        current = result.get(key)
        if current is None:
            result[key] = data
            continue
        current_score = sum(bool(normalize_text(current.get(c, ""))) for c in score_cols)
        new_score = sum(bool(normalize_text(data.get(c, ""))) for c in score_cols)
        if new_score >= current_score:
            result[key] = data
    return result


def migrate_clientes_from_titulos() -> int:
    conn = get_conn()
    tit = pd.read_sql_query(
        """
        SELECT cliente_codigo, loja, nome_cliente, vendedor, gerente, observacao_atual
          FROM titulos
         WHERE cliente_codigo IS NOT NULL AND nome_cliente IS NOT NULL
         ORDER BY updated_at DESC
        """,
        conn,
    )
    total = 0
    if not tit.empty:
        for _, r in tit.iterrows():
            cid = make_cliente_id(r.get("cliente_codigo", ""), r.get("loja", ""), r.get("nome_cliente", ""))
            if not cid.strip("|"):
                continue
            upsert_cliente_cadastro(
                conn,
                str(r.get("cliente_codigo", "")),
                str(r.get("loja", "")),
                str(r.get("nome_cliente", "")),
                str(r.get("vendedor", "") or ""),
                str(r.get("gerente", "") or ""),
                str(r.get("observacao_atual", "") or ""),
            )
            total += 1
    conn.commit()
    conn.close()
    return total


def safe_to_excel_bytes(sheets: Dict[str, pd.DataFrame]) -> bytes:
    """Exporta Excel com códigos preservados como texto e visual padronizado."""
    output = BytesIO()
    with pd.ExcelWriter(output, engine="openpyxl") as writer:
        for name, df in sheets.items():
            clean_name = str(name)[:31] or "Relatorio"
            export_df = df.copy()
            export_df.to_excel(writer, index=False, sheet_name=clean_name)
            ws = writer.book[clean_name]

            try:
                from openpyxl.styles import Alignment, Font, PatternFill
                from openpyxl.utils import get_column_letter

                header_fill = PatternFill("solid", fgColor="123E67")
                header_font = Font(color="FFFFFF", bold=True)
                for cell in ws[1]:
                    cell.fill = header_fill
                    cell.font = header_font
                    cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
                ws.freeze_panes = "A2"
                ws.auto_filter.ref = ws.dimensions
                ws.row_dimensions[1].height = 34

                text_tokens = ("COD", "CÓD", "LOJA", "CNPJ", "PRF", "NÚMERO", "NUMERO", "PARCELA", "TELEFONE", "TEL.")
                money_tokens = ("VALOR", "SALDO", "VENCIDOS", "A VENCER", "CORRIGIDO")
                date_tokens = ("DATA", "VENCTO", "VENCIMENTO", "EMISSÃO", "EMISSAO")

                for idx, column_name in enumerate(export_df.columns, start=1):
                    header = str(column_name).upper()
                    letter = get_column_letter(idx)
                    values = [str(column_name)] + [
                        "" if v is None or (isinstance(v, float) and pd.isna(v)) else str(v)
                        for v in export_df[column_name].head(500).tolist()
                    ]
                    width = min(max(max((len(v) for v in values), default=10) + 2, 10), 42)
                    ws.column_dimensions[letter].width = width

                    for cell in ws[letter][1:]:
                        cell.alignment = Alignment(vertical="top", wrap_text=True)
                        if any(token in header for token in text_tokens):
                            cell.number_format = "@"
                        elif any(token in header for token in money_tokens):
                            cell.number_format = 'R$ #,##0.00'
                        elif any(token in header for token in date_tokens):
                            cell.number_format = "dd/mm/yyyy"
            except Exception:
                pass
    return output.getvalue()


def _latest_history_for_titles(title_ids: List[str]) -> Dict[str, str]:
    ids = [str(x) for x in title_ids if str(x)]
    if not ids:
        return {}
    conn = get_conn()
    try:
        placeholders = ",".join(["?"] * len(ids))
        hist = pd.read_sql_query(
            f"""
            SELECT id, titulo_id, data_acao, tipo_acao, responsavel, observacao
              FROM historico_acoes
             WHERE titulo_id IN ({placeholders})
             ORDER BY data_acao DESC, id DESC
            """,
            conn,
            params=ids,
        )
    finally:
        conn.close()
    if hist.empty:
        return {}
    hist = hist.drop_duplicates("titulo_id", keep="first")
    result = {}
    for _, row in hist.iterrows():
        dt = pd.to_datetime(row.get("data_acao"), errors="coerce")
        data_txt = dt.strftime("%d/%m/%Y") if not pd.isna(dt) else normalize_text(row.get("data_acao"))
        parts = [data_txt, normalize_text(row.get("tipo_acao")), clean_history_text(row.get("observacao"))]
        result[str(row["titulo_id"])] = " - ".join([p for p in parts if p])
    return result


def _display_parcela(value) -> str:
    txt = normalize_text(value)
    if not txt:
        return ""
    digits = re.sub(r"\D+", "", txt)
    if not digits:
        return txt
    if digits == "0":
        return "0"
    return digits.zfill(3)


def build_standard_collection_report(df: pd.DataFrame) -> pd.DataFrame:
    """Monta o relatório operacional na ordem solicitada pela equipe."""
    headers = [
        "Codigo-Lj-Nome do Cliente", "N Fantasia", "Nome", "Vendedor", "Gerente", "Segmento",
        "Prf-Numero\nParcela", "TP",
        "Data de\nEmissao", "Vencto\nTitulo", "Vencto\nReal", "Bco St", "Valor Original",
        "Tit Vencidos\nValor Atual", "Titulos a Vencer\nValor Atual",
        "Tit Vencidos\nValor Corrigido", "Dias\nAtraso", "Hist.Cobranc",
        "Tel. Fin.", "Tel. Com."
    ]
    if df is None or df.empty:
        return pd.DataFrame(columns=headers)

    base = df.copy()
    defaults = {
        "titulo_id": "", "cliente_codigo": "", "loja": "", "nome_cliente": "",
        "nome_fantasia": "", "razao_social": "", "prefixo": "", "numero_titulo": "",
        "parcela": "", "tipo": "", "dt_emissao": "", "vencimento_titulo": "",
        "vencimento": "", "banco_status": "", "valor_titulo": 0.0, "saldo_atual": 0.0,
        "saldo_corrigido": 0.0, "multa": 0.0, "juros": 0.0, "dias_atraso": 0,
        "observacao_atual": "", "telefone_financeiro": "", "telefone_comercial": "",
        "vendedor": "", "gerente": "", "segmento": "",
    }
    for col, default in defaults.items():
        if col not in base.columns:
            base[col] = default

    history_map = _latest_history_for_titles(base["titulo_id"].astype(str).tolist())
    today_ref = date.today()

    rows = []
    for _, r in base.iterrows():
        codigo = format_identifier(r.get("cliente_codigo"), 6)
        loja = format_identifier(r.get("loja"), 2)
        fantasia = upper_text(r.get("nome_fantasia") or r.get("nome_cliente"))
        razao = upper_text(r.get("razao_social") or r.get("nome_cliente"))
        nome_composto = razao or fantasia
        prefixo = upper_text(r.get("prefixo"))
        numero = format_identifier(r.get("numero_titulo"), 6)
        parcela = _display_parcela(r.get("parcela"))

        venc_real = parse_iso_date(normalize_text(r.get("vencimento")))
        venc_titulo = parse_iso_date(normalize_text(r.get("vencimento_titulo"))) or venc_real
        emissao = parse_iso_date(normalize_text(r.get("dt_emissao")))
        dias = r.get("dias_atraso")
        try:
            dias = int(dias)
        except Exception:
            dias = calcular_dias_atraso(normalize_text(r.get("vencimento")), today_ref)

        saldo = float(r.get("saldo_atual") or 0)
        valor_original = float(r.get("valor_titulo") or 0)
        saldo_corrigido = float(r.get("saldo_corrigido") or 0)
        if saldo_corrigido <= 0:
            saldo_corrigido = saldo + float(r.get("multa") or 0) + float(r.get("juros") or 0)

        vencido = saldo if dias > 0 else 0.0
        a_vencer = saldo if dias <= 0 else 0.0
        latest = history_map.get(str(r.get("titulo_id")), "")
        obs = clean_history_text(r.get("observacao_atual"))
        hist = latest or obs

        rows.append({
            "Codigo-Lj-Nome do Cliente": f"{codigo}-{loja}-{nome_composto}".strip("-"),
            "N Fantasia": fantasia,
            "Nome": razao,
            "Vendedor": canonical_vendor_display(r.get("vendedor")) or upper_text(r.get("vendedor")),
            "Gerente": canonical_manager_display(r.get("gerente")) or upper_text(r.get("gerente")),
            "Segmento": canonical_segment_display(r.get("segmento")) or upper_text(r.get("segmento")),
            "Prf-Numero\nParcela": f"{prefixo}-{numero}\n{parcela}".strip("-\n"),
            "TP": upper_text(r.get("tipo")),
            "Data de\nEmissao": emissao,
            "Vencto\nTitulo": venc_titulo,
            "Vencto\nReal": venc_real,
            "Bco St": upper_text(r.get("banco_status")),
            "Valor Original": valor_original,
            "Tit Vencidos\nValor Atual": vencido,
            "Titulos a Vencer\nValor Atual": a_vencer,
            "Tit Vencidos\nValor Corrigido": saldo_corrigido if dias > 0 else 0.0,
            "Dias\nAtraso": dias,
            "Hist.Cobranc": hist,
            "Tel. Fin.": upper_text(r.get("telefone_financeiro")),
            "Tel. Com.": upper_text(r.get("telefone_comercial")),
        })
    return pd.DataFrame(rows, columns=headers)

def update_cliente_fields(cliente_codigo: str, loja: str, nome_cliente: str, vendedor: str, gerente: str, observacao: str) -> int:
    backup_db("antes_responsaveis")
    conn = get_conn()
    try:
        where, params = _cliente_where_clause(cliente_codigo, loja, nome_cliente)
        now = datetime.now().isoformat(timespec="seconds")
        upsert_cliente_cadastro(conn, cliente_codigo, loja, nome_cliente, vendedor=vendedor, gerente=gerente, observacao=observacao)
        cur = conn.execute(
            f"""
            UPDATE titulos
               SET vendedor = ?, gerente = ?, observacao_atual = ?, updated_at = ?
             WHERE {where} AND status != ?
            """,
            [upper_text(vendedor), upper_text(gerente), upper_text(observacao), now] + params + [STATUS_PAGO],
        )
        conn.commit()
        return cur.rowcount
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def add_action(titulo_id: str, data_acao: date, tipo: str, responsavel: str, observacao: str, promessa: Optional[date]) -> None:
    conn = get_conn()
    now = datetime.now().isoformat(timespec="seconds")
    promessa_str = promessa.isoformat() if promessa else None
    conn.execute(
        """
        INSERT INTO historico_acoes (titulo_id, data_acao, tipo_acao, responsavel, observacao, promessa_pagamento, created_at)
        VALUES (?, ?, ?, ?, ?, ?, ?)
        """,
        (titulo_id, data_acao.isoformat(), tipo, upper_text(responsavel), upper_text(observacao), promessa_str, now),
    )
    if promessa_str:
        conn.execute(
            "UPDATE titulos SET promessa_pagamento = ?, status = ?, updated_at = ? WHERE titulo_id = ?",
            (promessa_str, STATUS_PROMESSA, now, titulo_id),
        )
    elif tipo == "Pagamento identificado manualmente":
        conn.execute(
            "UPDATE titulos SET status = ?, data_baixa = ?, updated_at = ? WHERE titulo_id = ?",
            (STATUS_PAGO, data_acao.isoformat(), now, titulo_id),
        )
    conn.commit()
    conn.close()





def save_cliente_all(
    cliente_codigo: str,
    loja: str,
    nome_cliente: str,
    tipo_cliente: str,
    cobrador: str,
    razao_social: str,
    cnpj: str,
    contato: str,
    nome_fantasia: str,
    telefone_financeiro: str,
    telefone_comercial: str,
    endereco: str,
    bairro: str,
    municipio: str,
    uf: str,
    cep: str,
    email_nfe: str,
    email_comercial: str,
    email_financeiro: str,
    vendedor: str,
    gerente: str,
    observacao_cliente: str,
    tipo_acao: str,
    responsavel_acao: str,
    data_acao: date,
    observacao_acao: str,
    promessa: Optional[date],
    agendar_retorno: bool,
    data_retorno: Optional[date],
    motivo_retorno: str,
) -> Dict[str, object]:
    """Salva todos os campos do cliente em uma única transação.

    Evita que um campo salvo por último sobrescreva outro campo com valor antigo.
    Também garante que o histórico, a promessa e a agenda sejam gravados juntos ou nada seja salvo.
    """
    backup_db("antes_salvar_cliente_completo")
    conn = get_conn()
    try:
        now = datetime.now().isoformat(timespec="seconds")
        cliente_codigo = format_identifier(cliente_codigo, 6)
        loja = format_identifier(loja, 2)
        cid = make_cliente_id(cliente_codigo, loja, nome_cliente)
        tipo_cliente = (tipo_cliente or "Não especial").strip() or "Não especial"
        cobrador = upper_text(cobrador)
        razao_social = upper_text(razao_social)
        cnpj = upper_text(cnpj)
        contato = upper_text(contato)
        nome_fantasia = upper_text(nome_fantasia)
        telefone_financeiro = upper_text(telefone_financeiro)
        telefone_comercial = upper_text(telefone_comercial)
        endereco = upper_text(endereco)
        bairro = upper_text(bairro)
        municipio = upper_text(municipio)
        uf = upper_text(uf)
        cep = upper_text(cep)
        email_nfe = upper_text(email_nfe)
        email_comercial = upper_text(email_comercial)
        email_financeiro = upper_text(email_financeiro)
        vendedor = upper_text(vendedor)
        gerente = upper_text(gerente)
        observacao_cliente = upper_text(observacao_cliente)
        responsavel_acao = upper_text(responsavel_acao or cobrador or current_user_name() or "Financeiro")
        observacao_acao = upper_text(clean_history_text(observacao_acao or ""))

        # Segurança operacional: se a usuária digitou uma observação de ação, ela deve ir para o histórico,
        # mesmo que tenha esquecido de trocar o seletor que vem como "Não registrar ação agora".
        # A observação geral do cliente continua sendo salva como cadastro; a observação da ação vira histórico.
        if observacao_acao and (not tipo_acao or tipo_acao == "Não registrar ação agora"):
            tipo_acao = "Observação registrada"
        if agendar_retorno and (not tipo_acao or tipo_acao == "Não registrar ação agora"):
            tipo_acao = "Agendar retorno"
            if not observacao_acao:
                observacao_acao = upper_text(clean_history_text(motivo_retorno or "RETORNO PROGRAMADO"))

        # Cadastro do cliente: grava exatamente o que está na tela.
        conn.execute(
            """
            INSERT INTO clientes (
                cliente_id, cliente_codigo, loja, nome_cliente, vendedor, gerente, tipo_cliente, cobrador,
                observacao, razao_social, cnpj, contato, nome_fantasia, telefone_financeiro,
                telefone_comercial, endereco, bairro, municipio, uf, cep, email_nfe, email_comercial,
                email_financeiro, created_at, updated_at
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(cliente_id) DO UPDATE SET
                cliente_codigo = excluded.cliente_codigo,
                loja = excluded.loja,
                nome_cliente = excluded.nome_cliente,
                vendedor = excluded.vendedor,
                gerente = excluded.gerente,
                tipo_cliente = excluded.tipo_cliente,
                cobrador = excluded.cobrador,
                observacao = excluded.observacao,
                razao_social = excluded.razao_social,
                cnpj = excluded.cnpj,
                contato = excluded.contato,
                nome_fantasia = excluded.nome_fantasia,
                telefone_financeiro = excluded.telefone_financeiro,
                telefone_comercial = excluded.telefone_comercial,
                endereco = excluded.endereco,
                bairro = excluded.bairro,
                municipio = excluded.municipio,
                uf = excluded.uf,
                cep = excluded.cep,
                email_nfe = excluded.email_nfe,
                email_comercial = excluded.email_comercial,
                email_financeiro = excluded.email_financeiro,
                updated_at = excluded.updated_at
            """,
            (
                cid, format_identifier(cliente_codigo, 6), format_identifier(loja, 2), nome_cliente,
                vendedor, gerente, tipo_cliente, cobrador, observacao_cliente, razao_social, cnpj,
                contato, nome_fantasia, telefone_financeiro, telefone_comercial, endereco, bairro, municipio, uf, cep,
                email_nfe, email_comercial, email_financeiro, now, now
            ),
        )

        where, params = _cliente_where_clause(cliente_codigo, loja, nome_cliente)
        doc_save = cnpj_digits(cnpj)
        if len(doc_save) >= 11:
            # Atualiza todos os títulos do mesmo documento para evitar cobranças separadas
            # por ausência de código/loja ou variação cadastral.
            where = "REPLACE(REPLACE(REPLACE(REPLACE(COALESCE(cnpj, ''), '.', ''), '/', ''), '-', ''), ' ', '') = ?"
            params = [doc_save]

        cur = conn.execute(
            f"""
            UPDATE titulos
               SET vendedor = ?, gerente = ?, observacao_atual = ?, razao_social = ?, cnpj = ?, contato = ?,
                   nome_fantasia = ?, telefone_financeiro = ?, telefone_comercial = ?, updated_at = ?
             WHERE {where} AND status != ?
            """,
            [
                vendedor, gerente, observacao_cliente, razao_social, cnpj, contato,
                nome_fantasia, telefone_financeiro, telefone_comercial, now
            ] + params + [STATUS_PAGO],
        )
        titulos_atualizados = int(cur.rowcount or 0)

        total_acao = 0
        promessa_str = promessa.isoformat() if promessa else None
        if tipo_acao and tipo_acao != "Não registrar ação agora":
            titulos = pd.read_sql_query(
                f"SELECT titulo_id FROM titulos WHERE {where} AND status != ?",
                conn,
                params=params + [STATUS_PAGO],
            )
            ids = titulos["titulo_id"].astype(str).tolist() if not titulos.empty else []
            if ids:
                rows = [
                    (tid, data_acao.isoformat(), tipo_acao, responsavel_acao, observacao_acao, promessa_str, now)
                    for tid in ids
                ]
                conn.executemany(
                    """
                    INSERT INTO historico_acoes (titulo_id, data_acao, tipo_acao, responsavel, observacao, promessa_pagamento, created_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?)
                    """,
                    rows,
                )
                total_acao = len(rows)

                if promessa_str:
                    conn.execute(
                        f"UPDATE titulos SET promessa_pagamento = ?, status = ?, updated_at = ? WHERE {where} AND status != ?",
                        [promessa_str, STATUS_PROMESSA, now] + params + [STATUS_PAGO],
                    )
                elif tipo_acao == "Pagamento identificado manualmente":
                    conn.execute(
                        f"UPDATE titulos SET status = ?, data_baixa = ?, updated_at = ? WHERE {where} AND status != ?",
                        [STATUS_PAGO, data_acao.isoformat(), now] + params + [STATUS_PAGO],
                    )

        agenda_status = "não agendada"
        if agendar_retorno and data_retorno:
            data_iso = data_retorno.isoformat()
            motivo_limpo = upper_text(clean_history_text(motivo_retorno or observacao_acao or tipo_acao or "Retorno programado"))
            existente = conn.execute(
                """
                SELECT id
                  FROM agenda_retorno
                 WHERE cliente_id = ?
                   AND status = 'Pendente'
                 ORDER BY id DESC
                 LIMIT 1
                """,
                (cid,),
            ).fetchone()
            if existente:
                conn.execute(
                    """
                    UPDATE agenda_retorno
                       SET data_retorno = ?, motivo = ?, responsavel = ?, nome_cliente = ?, cliente_codigo = ?, loja = ?, updated_at = ?
                     WHERE id = ?
                    """,
                    (data_iso, motivo_limpo, responsavel_acao, nome_cliente, cliente_codigo, loja, now, int(existente[0])),
                )
                agenda_status = "atualizada"
            else:
                conn.execute(
                    """
                    INSERT INTO agenda_retorno (cliente_id, cliente_codigo, loja, nome_cliente, data_retorno, motivo, responsavel, status, created_at, updated_at)
                    VALUES (?, ?, ?, ?, ?, ?, ?, 'Pendente', ?, ?)
                    """,
                    (cid, cliente_codigo, loja, nome_cliente, data_iso, motivo_limpo, responsavel_acao, now, now),
                )
                agenda_status = "incluída"

        conn.commit()
        return {"titulos_atualizados": titulos_atualizados, "acoes_registradas": total_acao, "agenda": agenda_status}
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()

def add_action_cliente(cliente_codigo: str, loja: str, nome_cliente: str, data_acao: date, tipo: str, responsavel: str, observacao: str, promessa: Optional[date]) -> int:
    backup_db("antes_acao_cliente")
    """Registra uma única ação do CRM em todos os títulos abertos do cliente.

    A cobrança é feita uma vez por cliente, mesmo quando existem vários títulos.
    Para preservar rastreabilidade, a ação é gravada em cada título aberto daquele cliente.
    A gravação é transacional: se qualquer etapa falhar, nada é parcialmente salvo.
    """
    conn = get_conn()
    try:
        now = datetime.now().isoformat(timespec="seconds")
        promessa_str = promessa.isoformat() if promessa else None
        where, params = _cliente_where_clause(cliente_codigo, loja, nome_cliente)
        titulos = pd.read_sql_query(
            f"SELECT titulo_id FROM titulos WHERE {where} AND status != ?",
            conn,
            params=params + [STATUS_PAGO],
        )
        if titulos.empty:
            return 0

        rows = [
            (tid, data_acao.isoformat(), tipo, upper_text(responsavel), upper_text(observacao), promessa_str, now)
            for tid in titulos["titulo_id"].astype(str).tolist()
        ]
        conn.executemany(
            """
            INSERT INTO historico_acoes (titulo_id, data_acao, tipo_acao, responsavel, observacao, promessa_pagamento, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            rows,
        )
        if promessa_str:
            conn.execute(
                f"UPDATE titulos SET promessa_pagamento = ?, status = ?, updated_at = ? WHERE {where} AND status != ?",
                [promessa_str, STATUS_PROMESSA, now] + params + [STATUS_PAGO],
            )
        elif tipo == "Pagamento identificado manualmente":
            conn.execute(
                f"UPDATE titulos SET status = ?, data_baixa = ?, updated_at = ? WHERE {where} AND status != ?",
                [STATUS_PAGO, data_acao.isoformat(), now] + params + [STATUS_PAGO],
            )
        conn.commit()
        return len(rows)
    except Exception:
        conn.rollback()
        raise
    finally:
        conn.close()


def save_regua(df: pd.DataFrame) -> None:
    conn = get_conn()
    cur = conn.cursor()
    cur.execute("DELETE FROM regua_cobranca")
    rows = []
    for _, r in df.iterrows():
        try:
            dia = int(r.get("dia"))
        except Exception:
            continue
        if dia <= 0:
            continue
        rows.append((
            dia,
            upper_text(r.get("acao", "")),
            upper_text(r.get("descricao", "")),
            upper_text(r.get("responsavel_padrao", "Financeiro")),
            int(r.get("prioridade", 5) or 5),
        ))
    cur.executemany(
        "INSERT OR REPLACE INTO regua_cobranca (dia, acao, descricao, responsavel_padrao, prioridade) VALUES (?, ?, ?, ?, ?)",
        rows,
    )
    conn.commit()
    conn.close()


def prepare_fila(ref: date) -> pd.DataFrame:
    df = load_titulos()
    if df.empty:
        return df

    open_df = df[df["status"] != STATUS_PAGO].copy()
    if open_df.empty:
        return open_df

    # Normaliza a identificação antes de agrupar. Isso impede que o mesmo cliente
    # apareça duas vezes apenas porque parte dos títulos veio como 4079/1 e outra
    # parte como 004079/01 após o enriquecimento cadastral.
    open_df["cliente_codigo"] = open_df["cliente_codigo"].apply(lambda x: format_identifier(x, 6))
    open_df["loja"] = open_df["loja"].apply(lambda x: format_identifier(x, 2))
    open_df["nome_cliente"] = open_df["nome_cliente"].apply(lambda x: upper_text(normalize_text(x)))

    open_df["dias_atraso"] = open_df["vencimento"].apply(lambda x: calcular_dias_atraso(x, ref))
    open_df["ciclo_cobranca"] = open_df["primeira_aparicao"].apply(lambda x: calcular_ciclo(x, ref))
    open_df["vendedor"] = open_df.get("vendedor", "").apply(canonical_vendor_display)
    open_df["gerente"] = open_df.get("gerente", "").apply(canonical_manager_display)
    if "segmento" not in open_df.columns:
        open_df["segmento"] = ""
    open_df["segmento"] = open_df["segmento"].apply(canonical_segment_display)
    open_df["cliente_id"] = open_df.apply(
        lambda r: make_cliente_id(r.get("cliente_codigo", ""), r.get("loja", ""), r.get("nome_cliente", "")), axis=1
    )

    actions = open_df.apply(
        lambda r: get_action_for_day(int(r["ciclo_cobranca"]), str(r["status"]), r.get("promessa_pagamento"), ref), axis=1
    )
    open_df["acao_do_dia"] = [a["acao"] for a in actions]
    open_df["descricao_acao"] = [a["descricao"] for a in actions]
    open_df["responsavel_padrao"] = [a["responsavel_padrao"] for a in actions]
    open_df["prioridade"] = [a["prioridade"] for a in actions]
    open_df["valor_prioridade"] = open_df["saldo_atual"].fillna(0) * (open_df["dias_atraso"].fillna(0) + 1)

    return open_df.sort_values(["prioridade", "valor_prioridade"], ascending=[True, False])




def _join_unique(values: pd.Series, limite: int = 3) -> str:
    vals = []
    for v in values.fillna("").astype(str):
        v = v.strip()
        if v and v not in vals:
            vals.append(v)
    if len(vals) > limite:
        return ", ".join(vals[:limite]) + "..."
    return ", ".join(vals)


def _single_or_multiple(values: pd.Series, kind: str = "text") -> str:
    vals = []
    for raw in values.fillna("").astype(str):
        if kind == "vendedor":
            value = canonical_vendor_display(raw)
        elif kind == "gerente":
            value = canonical_manager_display(raw)
        elif kind == "segmento":
            value = canonical_segment_display(raw)
        else:
            value = normalize_text(raw)
        if value and value not in vals:
            vals.append(value)
    if not vals:
        return ""
    if len(vals) == 1:
        return vals[0]
    return "Vários"


def prepare_fila_clientes(ref: date) -> pd.DataFrame:
    """Agrupa a fila por cliente para que 15 títulos gerem uma única ação."""
    fila = prepare_fila(ref)
    if fila.empty:
        return fila

    conn = get_conn()
    cad_map = get_cliente_cadastro_map(conn)
    conn.close()

    rows = []
    fila = fila.copy()
    fila["_cliente_cobranca_key"] = fila.apply(cliente_cobranca_key, axis=1)
    for key_cobranca, grp in fila.groupby("_cliente_cobranca_key", dropna=False):
        # Usa o registro mais completo/recente como representante visual do grupo.
        grp_rep = grp.copy()
        grp_rep["_complete_score"] = grp_rep.apply(
            lambda r: sum(bool(normalize_text(r.get(c, ""))) for c in ["cnpj", "razao_social", "nome_fantasia", "vendedor", "gerente"]),
            axis=1,
        )
        rep = grp_rep.sort_values("_complete_score", ascending=False).iloc[0]
        cliente_codigo = str(rep.get("cliente_codigo", ""))
        loja = str(rep.get("loja", ""))
        nome_cliente = str(rep.get("nome_cliente", ""))
        max_ciclo = int(grp["ciclo_cobranca"].max())
        max_dias = int(grp["dias_atraso"].max())
        min_venc = grp["vencimento"].min()

        promessas_validas = []
        for p in grp.get("promessa_pagamento", pd.Series(dtype=str)).dropna().astype(str):
            dtp = parse_iso_date(p)
            if dtp and dtp >= ref:
                promessas_validas.append(dtp)
        promessa_cliente = min(promessas_validas).isoformat() if promessas_validas else None

        cid = make_cliente_id(cliente_codigo, loja, nome_cliente)
        cad = cad_map.get(cid, {})
        if not cad:
            doc_grp = cnpj_digits(_join_unique(grp.get("cnpj", pd.Series(dtype=str)), limite=1))
            if len(doc_grp) >= 11:
                for _cad in cad_map.values():
                    if cnpj_digits(_cad.get("cnpj", "")) == doc_grp:
                        cad = _cad
                        break
        tipo_cliente = str(cad.get("tipo_cliente", "") or "Não especial")
        cobrador = str(cad.get("cobrador", "") or "")
        razao_social = str(cad.get("razao_social", "") or _join_unique(grp.get("razao_social", pd.Series(dtype=str)), limite=1) or "")
        cnpj = str(cad.get("cnpj", "") or _join_unique(grp.get("cnpj", pd.Series(dtype=str)), limite=1) or "")
        contato = str(cad.get("contato", "") or _join_unique(grp.get("contato", pd.Series(dtype=str)), limite=1) or "")
        nome_fantasia = str(cad.get("nome_fantasia", "") or _join_unique(grp.get("nome_fantasia", pd.Series(dtype=str)), limite=1) or nome_cliente)
        telefone_financeiro = str(cad.get("telefone_financeiro", "") or _join_unique(grp.get("telefone_financeiro", pd.Series(dtype=str)), limite=1) or "")
        telefone_comercial = str(cad.get("telefone_comercial", "") or _join_unique(grp.get("telefone_comercial", pd.Series(dtype=str)), limite=1) or "")
        endereco = str(cad.get("endereco", "") or "")
        bairro = str(cad.get("bairro", "") or "")
        municipio = str(cad.get("municipio", "") or "")
        uf = str(cad.get("uf", "") or "")
        cep = str(cad.get("cep", "") or "")
        email_nfe = str(cad.get("email_nfe", "") or "")
        email_comercial = str(cad.get("email_comercial", "") or "")
        email_financeiro = str(cad.get("email_financeiro", "") or "")
        notif_data_contrato = str(cad.get("notif_data_contrato", "") or "")
        notif_contraprestacao = str(cad.get("notif_contraprestacao", "") or "")
        notif_prazo = str(cad.get("notif_prazo", "") or "")
        notif_teams_link = str(cad.get("notif_teams_link", "") or "")
        notif_assinatura = str(cad.get("notif_assinatura", "") or "")
        acao = get_action_for_day(max_ciclo, str(grp["status"].iloc[0]), promessa_cliente, ref)
        rows.append({
            "cliente_id": str(key_cobranca),
            "cliente_codigo": cliente_codigo,
            "loja": loja,
            "nome_cliente": nome_cliente,
            "qtd_titulos": int(grp["titulo_id"].nunique()),
            "saldo_total": float(grp["saldo_atual"].sum()),
            "menor_vencimento": min_venc,
            "maior_dias_atraso": max_dias,
            "dia_regua": max_ciclo,
            "acao_do_dia": acao["acao"],
            "descricao_acao": acao["descricao"],
            "responsavel_padrao": acao["responsavel_padrao"],
            "prioridade": int(acao["prioridade"]),
            "vendedor": _single_or_multiple(grp["vendedor"], "vendedor"),
            "gerente": _single_or_multiple(grp["gerente"], "gerente"),
            "segmento": _single_or_multiple(grp["segmento"], "segmento"),
            "tipo_cliente": tipo_cliente,
            "cobrador": cobrador,
            "razao_social": razao_social,
            "cnpj": cnpj,
            "contato": contato,
            "nome_fantasia": nome_fantasia,
            "telefone_financeiro": telefone_financeiro,
            "telefone_comercial": telefone_comercial,
            "endereco": endereco,
            "bairro": bairro,
            "municipio": municipio,
            "uf": uf,
            "cep": cep,
            "email_nfe": email_nfe,
            "email_comercial": email_comercial,
            "email_financeiro": email_financeiro,
            "notif_data_contrato": notif_data_contrato,
            "notif_contraprestacao": notif_contraprestacao,
            "notif_prazo": notif_prazo,
            "notif_teams_link": notif_teams_link,
            "notif_assinatura": notif_assinatura,
            "notas_cliente": ", ".join(sorted(set([normalize_note_key(v) for v in grp.get("numero_titulo", pd.Series(dtype=str)).tolist() if normalize_note_key(v)]))),
            "variacoes_cadastro": int(grp[["cliente_codigo", "loja", "nome_cliente"]].drop_duplicates().shape[0]),
            "chave_cobranca": str(key_cobranca),
            "razoes_busca": " ".join([str(razao_social or ""), str(nome_fantasia or ""), str(nome_cliente or "")]),
            "valor_prioridade": float(grp["saldo_atual"].sum()) * (max_dias + 1),
        })
    out = pd.DataFrame(rows)
    return out.sort_values(["prioridade", "valor_prioridade"], ascending=[True, False])




def apply_fila_filters(fila: pd.DataFrame, prefix: str = "fila") -> pd.DataFrame:
    """Aplica filtros salvos em session_state. Usado pela fila e pela tela do cliente."""
    if fila.empty:
        return fila
    filtered = fila.copy()
    geral_search = str(st.session_state.get(f"{prefix}_geral", "") or "").strip()
    cliente_search = str(st.session_state.get(f"{prefix}_cliente", "") or "").strip()
    nf_search = normalize_note_key(st.session_state.get(f"{prefix}_nf", ""))
    razao_search = str(st.session_state.get(f"{prefix}_razao", "") or "").strip()
    cnpj_search = re.sub(r"\D+", "", str(st.session_state.get(f"{prefix}_cnpj", "") or ""))
    acao_filter = st.session_state.get(f"{prefix}_acao", "Todas")
    resp_filter = st.session_state.get(f"{prefix}_resp", "Todos")
    gerente_filter = st.session_state.get(f"{prefix}_gerente", "Todos")
    vendedor_filter = st.session_state.get(f"{prefix}_vendedor", "Todos")
    segmento_filter = st.session_state.get(f"{prefix}_segmento", "Todos")
    tipo_cliente_filter = st.session_state.get(f"{prefix}_tipo_cliente", "Todos")
    cobrador_filter = st.session_state.get(f"{prefix}_cobrador", "Todos")

    if geral_search:
        geral = normalize_text(geral_search).upper()
        geral_digits = re.sub(r"\D+", "", geral_search)
        geral_nf = normalize_note_key(geral_search)
        busca_cols = []
        for col in ["nome_cliente", "razao_social", "nome_fantasia", "cnpj", "notas_cliente", "vendedor", "gerente", "segmento", "cobrador"]:
            if col in filtered.columns:
                busca_cols.append(filtered[col].fillna("").astype(str))
        if busca_cols:
            busca_serie = busca_cols[0]
            for serie in busca_cols[1:]:
                busca_serie = busca_serie + " " + serie
            busca_serie = busca_serie.astype(str).str.upper()
            mask_geral = busca_serie.str.contains(re.escape(geral), na=False)
            if geral_digits and "cnpj" in filtered.columns:
                mask_geral = mask_geral | filtered["cnpj"].astype(str).str.replace(r"\D+", "", regex=True).str.contains(re.escape(geral_digits), na=False)
            if geral_nf and "notas_cliente" in filtered.columns:
                mask_geral = mask_geral | filtered["notas_cliente"].astype(str).apply(lambda x: geral_nf in {normalize_note_key(v) for v in re.split(r"[,;\s]+", x) if normalize_note_key(v)})
            filtered = filtered[mask_geral]
    if cliente_search:
        nome_mask = filtered["nome_cliente"].astype(str).str.contains(cliente_search, case=False, na=False)
        if "nome_fantasia" in filtered.columns:
            nome_mask = nome_mask | filtered["nome_fantasia"].astype(str).str.contains(cliente_search, case=False, na=False)
        filtered = filtered[nome_mask]
    if nf_search and "notas_cliente" in filtered.columns:
        filtered = filtered[filtered["notas_cliente"].astype(str).apply(lambda x: nf_search in {normalize_note_key(v) for v in re.split(r"[,;\s]+", x) if normalize_note_key(v)})]
    if cnpj_search and "cnpj" in filtered.columns:
        filtered = filtered[filtered["cnpj"].astype(str).str.replace(r"\D+", "", regex=True).str.contains(re.escape(cnpj_search), na=False)]
    if razao_search:
        if "razoes_busca" in filtered.columns:
            filtered = filtered[filtered["razoes_busca"].astype(str).str.contains(razao_search, case=False, na=False)]
        elif "razao_social" in filtered.columns:
            filtered = filtered[filtered["razao_social"].astype(str).str.contains(razao_search, case=False, na=False)]
    if acao_filter and acao_filter != "Todas":
        filtered = filtered[filtered["acao_do_dia"] == acao_filter]
    if resp_filter == "Sem vendedor ou gerente":
        filtered = filtered[(filtered["vendedor"].fillna("") == "") | (filtered["gerente"].fillna("") == "")]
    elif resp_filter == "Sem vendedor":
        filtered = filtered[filtered["vendedor"].fillna("") == ""]
    elif resp_filter == "Sem gerente":
        filtered = filtered[filtered["gerente"].fillna("") == ""]
    if gerente_filter and gerente_filter != "Todos":
        filtered = filtered[filtered["gerente"].replace("", "Sem gerente") == gerente_filter]
    if vendedor_filter and vendedor_filter != "Todos":
        filtered = filtered[filtered["vendedor"].replace("", "Sem vendedor") == vendedor_filter]
    if segmento_filter and segmento_filter != "Todos":
        filtered = filtered[filtered["segmento"].replace("", "Sem segmento") == segmento_filter]
    if tipo_cliente_filter and tipo_cliente_filter != "Todos":
        filtered = filtered[filtered["tipo_cliente"].fillna("Não especial") == tipo_cliente_filter]
    if cobrador_filter and cobrador_filter != "Todos":
        filtered = filtered[filtered["cobrador"].replace("", "Sem cobrador") == cobrador_filter]
    return filtered


def set_fila_filter(page_name: str = "Fila por cliente", **filters) -> None:
    """Define filtros e leva o usuário para a tela de fila/cliente."""
    for k, v in filters.items():
        st.session_state[k] = v
    st.session_state["_pending_nav_page"] = page_name
    st.session_state["cliente_index"] = 0
    st.rerun()


def advance_cliente_index(total_options: int) -> None:
    if total_options <= 0:
        st.session_state["cliente_index"] = 0
    else:
        atual = int(st.session_state.get("cliente_index", 0) or 0)
        st.session_state["cliente_index"] = min(atual + 1, total_options - 1)

def load_titulos_cliente(cliente_codigo: str, loja: str, nome_cliente: str, somente_abertos: bool = True) -> pd.DataFrame:
    conn = get_conn()
    where, params = _cliente_where_clause(cliente_codigo, loja, nome_cliente)

    # Se o cliente possui CNPJ/CPF identificado, a cobrança deve considerar todos os
    # títulos do mesmo documento, mesmo que algum relatório tenha vindo sem código,
    # com loja diferente ou com pequena variação de nome.
    doc = ""
    try:
        doc_row = conn.execute(
            f"SELECT cnpj FROM titulos WHERE {where} AND COALESCE(cnpj, '') != '' LIMIT 1",
            params,
        ).fetchone()
        if doc_row:
            doc = cnpj_digits(doc_row["cnpj"])
    except Exception:
        doc = ""

    if len(doc) >= 11:
        where = "REPLACE(REPLACE(REPLACE(REPLACE(COALESCE(cnpj, ''), '.', ''), '/', ''), '-', ''), ' ', '') = ?"
        params = [doc]

    query = f"SELECT * FROM titulos WHERE {where}"
    if somente_abertos:
        query += " AND status != ?"
        params = params + [STATUS_PAGO]
    df = pd.read_sql_query(query + " ORDER BY vencimento, numero_titulo, parcela", conn, params=params)
    conn.close()
    return df


def metric_card(label: str, value: str, help_text: str = "", long_text: bool = False) -> None:
    value_class = "metric-value long-text" if long_text else "metric-value"
    st.markdown(
        f"""
        <div class="metric-card" title="{html.escape(str(label))}: {html.escape(str(value))}">
            <div class="metric-label">{html.escape(str(label))}</div>
            <div class="{value_class}">{html.escape(str(value))}</div>
            <div class="metric-help">{html.escape(str(help_text))}</div>
        </div>
        """,
        unsafe_allow_html=True,
    )



