# Planilha de cálculo TJSP - preenchimento automático
# -----------------------------------------------------------------------------
def _excel_serial_from_date(value) -> Optional[int]:
    """Converte data para serial do Excel, preservando compatibilidade com o modelo XLSM."""
    dt = value if isinstance(value, date) else parse_iso_date(normalize_text(value))
    if not dt:
        return None
    return (dt - date(1899, 12, 30)).days


def _column_letters_to_index(col_letters: str) -> int:
    idx = 0
    for ch in col_letters.upper():
        if ch.isalpha():
            idx = idx * 26 + (ord(ch) - ord("A") + 1)
    return idx


def _cell_ref_to_col_row(ref: str) -> Tuple[str, int]:
    m = re.match(r"^([A-Z]+)(\d+)$", ref.upper())
    if not m:
        return "A", 1
    return m.group(1), int(m.group(2))


def _set_xlsx_cell_value(sheet_root, cell_ref: str, value, ns_main: str) -> None:
    col, row_num = _cell_ref_to_col_row(cell_ref)
    sheet_data = sheet_root.find(f"{{{ns_main}}}sheetData")
    if sheet_data is None:
        sheet_data = ET.SubElement(sheet_root, f"{{{ns_main}}}sheetData")

    row_el = None
    for r in sheet_data.findall(f"{{{ns_main}}}row"):
        if int(r.attrib.get("r", "0")) == row_num:
            row_el = r
            break
    if row_el is None:
        row_el = ET.Element(f"{{{ns_main}}}row", {"r": str(row_num)})
        inserted = False
        for i, r in enumerate(list(sheet_data)):
            if int(r.attrib.get("r", "0")) > row_num:
                sheet_data.insert(i, row_el)
                inserted = True
                break
        if not inserted:
            sheet_data.append(row_el)

    cell_el = None
    for c in row_el.findall(f"{{{ns_main}}}c"):
        if c.attrib.get("r") == cell_ref:
            cell_el = c
            break
    if cell_el is None:
        cell_el = ET.Element(f"{{{ns_main}}}c", {"r": cell_ref})
        target_idx = _column_letters_to_index(col)
        inserted = False
        for i, c in enumerate(list(row_el)):
            c_col, _ = _cell_ref_to_col_row(c.attrib.get("r", "A1"))
            if _column_letters_to_index(c_col) > target_idx:
                row_el.insert(i, cell_el)
                inserted = True
                break
        if not inserted:
            row_el.append(cell_el)

    for child in list(cell_el):
        if child.tag in {f"{{{ns_main}}}v", f"{{{ns_main}}}f", f"{{{ns_main}}}is"}:
            cell_el.remove(child)

    if value is None or value == "":
        cell_el.attrib.pop("t", None)
        return

    if isinstance(value, str):
        cell_el.attrib["t"] = "inlineStr"
        is_el = ET.SubElement(cell_el, f"{{{ns_main}}}is")
        t_el = ET.SubElement(is_el, f"{{{ns_main}}}t")
        t_el.text = value
    else:
        cell_el.attrib.pop("t", None)
        v_el = ET.SubElement(cell_el, f"{{{ns_main}}}v")
        v_el.text = str(float(value)) if isinstance(value, float) else str(value)


def _remove_calc_chain_references(xml_bytes: bytes, filename: str) -> bytes:
    """Remove referências ao calcChain para o Excel recalcular sem acusar corrupção."""
    try:
        if filename == "[Content_Types].xml":
            ns = "http://schemas.openxmlformats.org/package/2006/content-types"
            ET.register_namespace('', ns)
            root = ET.fromstring(xml_bytes)
            for child in list(root):
                if child.attrib.get("PartName") == "/xl/calcChain.xml":
                    root.remove(child)
            return ET.tostring(root, encoding="utf-8", xml_declaration=True)
        if filename == "xl/_rels/workbook.xml.rels":
            ns = "http://schemas.openxmlformats.org/package/2006/relationships"
            ET.register_namespace('', ns)
            root = ET.fromstring(xml_bytes)
            for child in list(root):
                target = str(child.attrib.get("Target", ""))
                rel_type = str(child.attrib.get("Type", ""))
                if target.endswith("calcChain.xml") or rel_type.endswith("/calcChain"):
                    root.remove(child)
            return ET.tostring(root, encoding="utf-8", xml_declaration=True)
    except Exception:
        return xml_bytes
    return xml_bytes



def _forcar_recalculo_excel_xlsm(xlsm_bytes: bytes) -> bytes:
    """Ajusta metadados do .xlsm para o Excel recalcular as fórmulas ao abrir.

    O openpyxl preserva fórmulas/macros, mas não calcula as fórmulas. Alguns
    Excels mantêm o valor em cache do modelo original. Este pós-processamento
    remove a cadeia antiga de cálculo e grava calcPr de forma explícita.
    """
    ns_main = "http://schemas.openxmlformats.org/spreadsheetml/2006/main"
    ns_rel = "http://schemas.openxmlformats.org/package/2006/relationships"
    ns_ct = "http://schemas.openxmlformats.org/package/2006/content-types"
    ET.register_namespace("", ns_main)
    ET.register_namespace("", ns_rel)

    src_zip = zipfile.ZipFile(BytesIO(xlsm_bytes), "r")
    output = BytesIO()

    with zipfile.ZipFile(output, "w", zipfile.ZIP_DEFLATED) as zout:
        for item in src_zip.infolist():
            if item.filename == "xl/calcChain.xml":
                continue

            data = src_zip.read(item.filename)

            if item.filename == "xl/workbook.xml":
                root = ET.fromstring(data)
                calc = root.find(f"{{{ns_main}}}calcPr")
                if calc is None:
                    calc = ET.SubElement(root, f"{{{ns_main}}}calcPr")
                calc.attrib["calcId"] = "0"
                calc.attrib["calcMode"] = "auto"
                calc.attrib["fullCalcOnLoad"] = "1"
                calc.attrib["forceFullCalc"] = "1"
                calc.attrib["calcOnSave"] = "1"
                data = ET.tostring(root, encoding="utf-8", xml_declaration=True)

            elif item.filename == "xl/_rels/workbook.xml.rels":
                root = ET.fromstring(data)
                for rel in list(root):
                    if str(rel.attrib.get("Type", "")).endswith("/calcChain"):
                        root.remove(rel)
                data = ET.tostring(root, encoding="utf-8", xml_declaration=True)

            elif item.filename == "[Content_Types].xml":
                root = ET.fromstring(data)
                for node in list(root):
                    if node.attrib.get("PartName") == "/xl/calcChain.xml":
                        root.remove(node)
                data = ET.tostring(root, encoding="utf-8", xml_declaration=True)

            zout.writestr(item, data)

    src_zip.close()
    output.seek(0)
    return output.getvalue()



def _recalcular_xlsm_com_libreoffice(xlsm_bytes: bytes) -> Tuple[bytes, str]:
    """Tenta recalcular o .xlsm em modo headless usando LibreOffice, quando disponível.

    Isso resolve modelos em que o Excel mantém cache antigo de fórmulas. Em ambientes
    sem LibreOffice, retorna o arquivo original e uma mensagem informativa.
    """
    soffice = shutil.which("libreoffice") or shutil.which("soffice")
    if not soffice:
        return xlsm_bytes, "LibreOffice não disponível no servidor; arquivo marcado para recalcular ao abrir no Excel."

    with tempfile.TemporaryDirectory() as tmpdir:
        tmpdir_path = Path(tmpdir)
        src_path = tmpdir_path / "calculo_tjsp.xlsm"
        src_path.write_bytes(xlsm_bytes)
        profile_dir = tmpdir_path / "lo_profile"
        profile_dir.mkdir(exist_ok=True)
        cmd = [
            soffice,
            "--headless",
            "--invisible",
            "--nodefault",
            "--nofirststartwizard",
            "--nolockcheck",
            f"-env:UserInstallation=file://{profile_dir.as_posix()}",
            "--convert-to",
            "xlsm",
            "--outdir",
            tmpdir_path.as_posix(),
            src_path.as_posix(),
        ]
        try:
            subprocess.run(cmd, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE, timeout=45)
        except Exception as exc:
            return xlsm_bytes, f"Não foi possível recalcular no servidor; arquivo marcado para recalcular ao abrir no Excel. Detalhe: {exc}"

        candidates = sorted(tmpdir_path.glob("*.xlsm"), key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)
        if candidates:
            data = candidates[0].read_bytes()
            if len(data) > 500:
                return data, "Planilha recalculada no servidor antes do download."
        return xlsm_bytes, "Recalculo no servidor não gerou novo arquivo; arquivo marcado para recalcular ao abrir no Excel."



def _excel_safe_percentual(value) -> Optional[float]:
    """Converte percentual digitado no app para formato aceito pelo Excel."""
    txt = normalize_text(value).replace("%", "").replace(".", "").replace(",", ".").strip()
    if not txt:
        return None
    try:
        val = float(txt)
    except Exception:
        return None
    # No Excel da planilha, 12% normalmente deve ser 12,0% = 0,12 quando formatado como percentual.
    # Se a usuária digitar 12, gravamos 0.12; se digitar 0.12, mantemos 0.12.
    if val > 1:
        val = val / 100
    return val


def _maior_data_indices_workbook(wb) -> Optional[date]:
    """Procura, de forma conservadora, a maior data encontrada nas abas de índices."""
    maior = None
    try:
        sheets = [ws for ws in wb.worksheets if "IND" in normalize_text(ws.title).upper()]
        if not sheets and len(wb.worksheets) > 1:
            sheets = wb.worksheets[1:]
        for ws in sheets:
            max_row = min(ws.max_row or 1, 2500)
            max_col = min(ws.max_column or 1, 30)
            for row in ws.iter_rows(min_row=1, max_row=max_row, min_col=1, max_col=max_col):
                for cell in row:
                    v = cell.value
                    dt = None
                    if isinstance(v, datetime):
                        dt = v.date()
                    elif isinstance(v, date):
                        dt = v
                    elif isinstance(v, str):
                        dt = parse_iso_date(normalize_text(v))
                    if dt and dt.year >= 1990:
                        maior = dt if maior is None or dt > maior else maior
    except Exception:
        return None
    return maior


def _validar_parametros_calculo_tjsp(wb, data_calculo: date, tabela_correcao: str) -> str:
    """Gera aviso preventivo sobre índices e parâmetros que impedem o cálculo."""
    avisos = []
    maior_indice = _maior_data_indices_workbook(wb)
    if maior_indice:
        primeiro_mes_calculo = date(data_calculo.year, data_calculo.month, 1)
        if date(maior_indice.year, maior_indice.month, 1) < primeiro_mes_calculo:
            avisos.append(
                "Atenção: a aba de índices parece ir até "
                f"{maior_indice.strftime('%m/%Y')}. Se a data final for {data_calculo.strftime('%m/%Y')}, "
                "o Índice Final pode ficar zerado; use modelo mais atualizado ou calcule até o último mês disponível."
            )
    if not normalize_text(tabela_correcao).strip():
        avisos.append("Atenção: tabela de correção monetária não informada.")
    return " ".join(avisos)


def preencher_calculo_tjsp_xlsm(template_bytes: bytes, titulos_df: pd.DataFrame, cliente_nome: str, data_calculo: date, razao_social: str = "", natureza_calculo: str = "CIVEL / PENAL", juros_opcao: str = "CC/02 (6% até 10/1/3; 12%)", juros_percentual: str = "", tabela_correcao: str = "TABELA PRÁTICA - INPC", juros_precedem_vencimento: str = "Não", termo_inicial_juros: Optional[date] = None) -> tuple[bytes, str]:
    """Preenche o modelo Cálculo Inicial FUABC.xlsm preservando compatibilidade com Excel.

    A geração por manipulação direta do XML funcionava para alguns modelos, mas
    continuava gerando aviso de corrupção em determinados Excels. Esta versão usa
    o próprio mecanismo do openpyxl com keep_vba=True, preservando o pacote .xlsm,
    fórmulas, estilos e macros do modelo oficial.
    """
    if not template_bytes:
        raise ValueError("Envie o modelo .xlsm de cálculo.")

    tit = titulos_df.copy() if titulos_df is not None else pd.DataFrame()
    if tit.empty:
        raise ValueError("Não há títulos abertos para preencher no cálculo.")
    if len(tit) > 570:
        raise ValueError("O modelo suporta até 570 linhas de títulos nesta versão.")

    tit["_venc_sort"] = tit.get("vencimento", pd.Series(dtype=str)).apply(lambda v: parse_iso_date(normalize_text(v)) or date.max)
    tit["_valor_calc"] = tit.apply(_valor_notificacao, axis=1)
    tit = tit.sort_values(["_venc_sort", "numero_titulo", "parcela"], kind="stable")

    # Valida o pacote de entrada antes de abrir no Excel writer.
    try:
        with zipfile.ZipFile(BytesIO(template_bytes), "r") as z:
            bad = z.testzip()
            if bad:
                raise ValueError(f"O modelo .xlsm está com problema interno no arquivo: {bad}")
    except zipfile.BadZipFile as exc:
        raise ValueError("O modelo enviado não é um .xlsm válido.") from exc

    try:
        from openpyxl import load_workbook
    except Exception as exc:
        raise RuntimeError("Inclua openpyxl no requirements.txt para preencher o modelo .xlsm.") from exc

    try:
        wb = load_workbook(BytesIO(template_bytes), keep_vba=True)
    except Exception as exc:
        raise ValueError(f"Não consegui abrir o modelo .xlsm pelo mecanismo do Excel: {exc}") from exc

    # Usa a primeira aba, mantendo a estrutura original do modelo.
    ws = wb.worksheets[0]

    # Campos principais do modelo, conforme orientação da planilha TJSP.
    # Observação: o modelo atual usa I20/J20 para juros, I35 para tabela e I37 para termo inicial.
    reu_completo = normalize_text(razao_social or cliente_nome).upper()
    ws["D19"] = data_calculo
    ws["B23"] = normalize_text(natureza_calculo or "CIVEL / PENAL")
    ws["I20"] = normalize_text(juros_opcao or "CC/02 (6%ªª até 10/1/3; 12%ªª até 29/8/24; depois, Selic menos correção)")
    perc_juros = _excel_safe_percentual(juros_percentual)
    if perc_juros is not None:
        ws["J20"] = perc_juros
    ws["D29"] = "AUTORA: FIRST MEDICAL SERVICE LTDA"
    ws["D30"] = f"RÉU: {reu_completo}"

    # Bloco principal da condenação: para múltiplas parcelas vencidas, por padrão
    # os juros não precedem os vencimentos e as datas ficam na coluna B.
    ws["I35"] = normalize_text(tabela_correcao or "TABELA PRÁTICA - INPC")
    ws["O34"] = normalize_text(juros_precedem_vencimento or "Não")
    ws["I37"] = termo_inicial_juros if termo_inicial_juros else None

    validacao_msg = _validar_parametros_calculo_tjsp(wb, data_calculo, tabela_correcao)

    # Limpa apenas os campos de entrada que o CRM preenche. Não mexe nas fórmulas.
    for row_num in range(40, 610):
        ws[f"B{row_num}"] = None
        ws[f"D{row_num}"] = None

    for i, (_, row) in enumerate(tit.iterrows(), start=40):
        venc = row.get("_venc_sort")
        ws[f"B{i}"] = venc if venc != date.max else None
        ws[f"D{i}"] = float(row.get("_valor_calc", 0) or 0)

    # Força recálculo ao abrir no Excel sem tentar recalcular dentro do Python.
    try:
        wb.calculation.fullCalcOnLoad = True
        wb.calculation.forceFullCalc = True
        wb.calculation.calcMode = "auto"
        wb.calculation.calcOnSave = True
        wb.calculation.calcId = 0
    except Exception:
        pass

    output = BytesIO()
    try:
        wb.save(output)
    except Exception as exc:
        raise ValueError(f"Não consegui salvar o .xlsm preenchido: {exc}") from exc

    output.seek(0)
    generated = output.getvalue()
    try:
        generated = _forcar_recalculo_excel_xlsm(generated)
    except Exception:
        pass

    generated, recalc_msg = _recalcular_xlsm_com_libreoffice(generated)

    # Validação final do pacote gerado. Isso não garante que o Excel vá recalcular,
    # mas garante que o arquivo entregue não está quebrado como ZIP/Office Open XML.
    try:
        with zipfile.ZipFile(BytesIO(generated), "r") as zcheck:
            bad = zcheck.testzip()
            if bad:
                raise ValueError(f"Arquivo gerado com problema interno em: {bad}")
            names = set(zcheck.namelist())
            if "[Content_Types].xml" not in names or "xl/workbook.xml" not in names:
                raise ValueError("Arquivo gerado não contém a estrutura básica de uma planilha Excel.")
    except zipfile.BadZipFile as exc:
        raise ValueError("O arquivo gerado não ficou em formato Excel válido.") from exc

    msg_final = recalc_msg
    if validacao_msg:
        msg_final = f"{msg_final} {validacao_msg}".strip()
    return generated, msg_final

def safe_xlsm_name(cliente_nome: str, data_calculo: date) -> str:
    return f"calculo_tjsp_{safe_filename(cliente_nome)}_{data_calculo.strftime('%Y%m%d')}.xlsm"

