                resumo_cols = [c for c in ["nome_cliente", "razao_social", "cnpj", "qtd_titulos", "saldo_total", "maior_dias_atraso", "variacoes_cadastro", "vendedor", "gerente", "notas_cliente"] if c in options.columns]
