        with c_tit:
            metric_card("Títulos", int(selected["qtd_titulos"]), "Quantidade em aberto")
        with c_atraso:
            metric_card("Maior atraso", f"{int(selected['maior_dias_atraso'])} dia(s)", "Maior vencimento em aberto")

